INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (1, 1, 28, 'dṛṣṭvemaṁ sva-janaṁ kṛṣṇa yuyutsuṁ samupasthitam', 'Seeing these, my kinsmen, O Krishna, arrayed, eager to fight,', 'Before any wisdom can land, something has to break. Arjuna looks at the battlefield and sees his own people on the other side. He freezes. Not because he''s weak, but because the situation is genuinely impossible. Sometimes the honest response to a crisis isn''t a plan. It''s just standing still long enough to feel how bad it really is.', 'Think of one situation you''re pretending is fine. Say out loud, to yourself: ''This is hard.'' That''s it. That''s the first step.', 'What crisis are you managing instead of actually feeling?', 'It is better to conquer grief than to deceive it.', 'Seneca, On Consolation to Helvia, 17.1b', 'Both the Gita and Seneca insist the first step through crisis is honest acknowledgment. You can''t skip the reckoning.', '{"clarity","courage"}', '{"paralysis","competing loyalties","honest reckoning with difficulty"}', 'When a major decision puts people you care about on different sides -- career vs. family, loyalty vs. integrity, two goods that cannot coexist.', 'C', 'The moment of paralysis when competing loyalties collide. Before any wisdom can land, the Gita validates the experience of being overwhelmed -- naming the crisis is the first act of clarity.', true, false, 'source: On Consolation to Helvia (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (2, 1, 47, 'evam uktvārjunaḥ saṅkhye rathopastha upāviśat', 'Having thus spoken in the midst of the battlefield, Arjuna, casting away his bow and arrow, sat down on the seat of the chariot with his mind overwhelmed with sorrow.', 'Arjuna drops his weapons and sits down. Right there on the battlefield. The greatest warrior of his generation just... stops. If that feels familiar, good. Sometimes the strongest thing you can do is admit you''ve hit the wall. Not forever. Just right now. Collapse isn''t the opposite of courage. Sometimes it''s the prerequisite.', 'If you''re exhausted right now, give yourself ten minutes of doing absolutely nothing. No phone. No guilt. Just sit.', 'When was the last time you let yourself fully stop before trying to fix something?', 'I judge you unfortunate because you have never lived through misfortune. You have passed through life without an opponent. No one can ever know what you are capable of, not even you.', 'Seneca, On Providence, 4.3', 'Both the Gita and Seneca see breakdown not as failure but as the furnace where real capability gets forged.', '{"acceptance","patience"}', '{"burnout","overwhelm","permission to break down","emotional honesty"}', 'In the aftermath of burnout, grief, or a public failure -- when you need permission to sit with the collapse before rushing to fix it.', 'C', 'Arjuna''s collapse is not weakness -- it is the body''s honest response to unbearable pressure. This verse normalizes breakdown as a legitimate stage in the journey toward right action.', true, false, 'source: On Providence (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (3, 2, 3, 'klaibyaṁ mā sma gamaḥ pārtha naitat tvayy upapadyate', 'Yield not to impotence, O Arjuna, son of Pritha! It does not befit thee. Cast off this mean weakness of the heart. Stand up, O scorcher of foes!', 'Sometimes the kindest thing someone can tell you is: enough. You''ve sat with the pain, you''ve honored it, and now it''s time to get up. Self-pity feels like processing, but past a certain point it''s just hiding.', 'Think of one thing you''ve been avoiding because it feels hard. Open it. Just look at it. You don''t have to finish it today.', 'What are you calling ''patience'' that might actually be avoidance?', 'How does it help, my husband, to make misfortune heavier by complaining about it? This is more fit for a king: to seize your adversities head on.', 'Seneca, Oedipus, 80', 'Both the Gita and Seneca deliver the same tough-love message: there''s a point where mourning becomes a way to avoid doing what you know needs doing.', '{"courage","discipline"}', '{"overcoming indecision","tough love","rising from self-pity"}', 'When you have been grieving or deliberating long enough and need someone to say ''get up'' -- the morning after a major setback.', 'A', 'The bracing mentor voice that says: enough wallowing. This is the verse that turns compassion into a call to action -- the kind of direct honesty most people never receive.', true, false, 'source: Oedipus (tragedy), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (4, 2, 7, 'kārpaṇya-doṣopahata-svabhāvaḥ pṛcchāmi tvāṁ dharma-sammūḍha-cetāḥ', 'My heart is overpowered by the taint of pity, my mind is confused as to duty. I ask Thee: tell me decisively what is good for me. I am Thy disciple. Instruct me who has taken refuge in Thee.', 'Arjuna does the hardest thing a capable person can do: he admits he''s lost. ''I don''t know what''s right. Tell me.'' Most people would rather make the wrong decision confidently than say those words. But every breakthrough in your life probably started the same way. You hit the limit of your own understanding and finally asked for help.', 'Think of one problem you''ve been trying to solve alone. Text someone who might help. Just one message.', 'What would you ask for help with if you weren''t afraid of looking weak?', 'For whatsoever it be that lieth upon thee to effect, thou must propose it unto thyself, as the scaling of walls is unto a soldier. And what if thou through either lameness or some other impediment art not able to reach unto the top of the battlements alone, which with the help of another thou mayst; wilt thou therefore give it over?', 'Marcus Aurelius, Meditations, 7.7', 'Both Arjuna and Marcus treat asking for help not as weakness but as tactical necessity. The soldier doesn''t abandon the wall just because he can''t climb it alone.', '{"clarity","acceptance"}', '{"asking for help","intellectual humility","admitting confusion"}', 'When you are stuck at a crossroads and pride is the only thing preventing you from reaching out to a mentor, therapist, or trusted friend.', 'C', 'Arjuna models the highest form of strength: admitting confusion and asking for guidance. In a culture that prizes self-sufficiency, this verse reframes ''I don''t know'' as the beginning of wisdom.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (5, 2, 11, 'aśocyān anvaśocas tvaṁ prajñā-vādāṁś ca bhāṣase', 'Thou hast grieved for those that should not be grieved for, yet thou speakest words of wisdom. The wise grieve neither for the living nor for the dead.', 'You''ve been making a very convincing case for the wrong side. The arguments are solid, your logic is sharp, but you already know the conclusion is off. That''s the hardest kind of self-deception to catch, because it sounds so reasonable.', 'Pick one opinion you''ve been defending lately. Ask yourself honestly: am I arguing for this because it''s true, or because it''s comfortable?', 'Where are you using good logic to protect a bad conclusion?', 'It is impossible for a man to begin to learn that which he thinks that he knows.', 'Epictetus, Discourses, 2.17.1', 'Both Krishna and Epictetus call out the same trap: sounding wise while avoiding what you actually know to be true.', '{"clarity","perspective"}', '{"intellectual dishonesty","emotional avoidance disguised as reason","self-deception"}', 'When you catch yourself arguing brilliantly for a position you know is wrong -- or when someone close to you is doing the same.', 'A', 'Krishna''s opening gambit cuts through Arjuna''s elaborate rationalizations. We all construct sophisticated arguments to avoid facing what we already know -- this verse exposes that pattern.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (6, 2, 14, 'mātrā-sparśās tu kaunteya śītoṣṇa-sukha-duḥkha-dāḥ', 'The contacts of the senses with the objects, O son of Kunti, which cause heat and cold and pleasure and pain, have a beginning and an end; they are impermanent; endure them bravely, O Arjuna!', 'That feeling you have right now? It has an expiration date. It showed up, and it will leave. This is true of the terrible days and, honestly, the great ones too. Your job isn''t to stop the weather. It''s to stop pretending the weather is permanent.', 'Next time a bad mood hits, set a timer for 90 minutes. Check if it still feels the same when the timer goes off.', 'What discomfort are you treating as permanent that''s actually just passing through?', 'To bear trials with a calm mind robs misfortune of its strength and burden.', 'Seneca, Hercules Oetaeus, 231-232', 'Both the Gita and Seneca agree: bearing difficulty calmly isn''t just noble. It actually takes the teeth out of the difficulty itself.', '{"patience","acceptance"}', '{"impermanence of emotions","endurance","weather vs. climate"}', 'During any period of discomfort that feels permanent -- a difficult boss, a health scare, a season of loneliness. The reminder: this too shall pass.', 'A', 'The foundational insight for emotional resilience: sensations, moods, and circumstances are weather systems that pass through you, not permanent features of your landscape. Endurance is a skill, not a trait.', true, false, 'source: Hercules Oetaeus (tragedy), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (7, 2, 15, 'yaṁ hi na vyathayanty ete puruṣaṁ puruṣarṣabha', 'That firm man whom surely these afflict not, O chief among men, to whom pleasure and pain are the same, is fit for attaining immortality!', 'The person who stays steady when things get bad and doesn''t get giddy when things go well isn''t numb. They''ve just stopped handing the remote control to their circumstances. That steadiness isn''t a personality trait. It''s a skill you build.', 'The next time something goes really well today, notice how quickly you start worrying about losing it. Just notice.', 'When was the last time your fear of something turned out to be worse than the thing itself?', 'Many are harmed by fear itself, and many may have come to their fate while dreading fate.', 'Seneca, Oedipus, 992', 'Both traditions point to the same insight: it''s rarely the pain itself that breaks you, but the flinching before it arrives.', '{"discipline","patience"}', '{"equanimity","emotional regulation","maturity under pressure"}', 'When emotional volatility makes you unreliable to yourself and others. When you want to build genuine equanimity, not just the appearance of calm.', 'B', 'Equanimity under pressure is not a personality trait but a practiced skill. The person who remains the same in pain and pleasure is not numb -- they have trained themselves to a stability that circumstances cannot reach.', true, false, 'source: Oedipus (tragedy), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (8, 2, 16, 'nāsato vidyate bhāvo nābhāvo vidyate sataḥ', 'The unreal hath no being; there is no non-being of the Real; the truth about both has been seen by the knowers of the Truth (or the seers of the Essence).', 'Most of what''s stressing you out right now isn''t real. It''s a story you built on top of what actually happened. Someone didn''t reply to your email. That''s the fact. ''They hate my work and I''m going to get fired'' is the fiction. Learning to tell the difference is basically a superpower.', 'Take whatever''s bothering you right now and strip it down to just the facts. No interpretation, no prediction. What actually happened?', 'What story are you telling yourself right now that you''ve confused with reality?', 'Keep thyself to the first bare and naked apprehensions of things, as they present themselves unto thee, and add not unto them. It is reported unto thee, that such a one speaketh ill of thee. Well; that he speaketh ill of thee, so much is reported. But that thou art hurt thereby, is not reported: that is the addition of opinion, which thou must exclude.', 'Marcus Aurelius, Meditations, 8.49', 'Both Krishna and Marcus say the same thing: stick to what''s actually in front of you and stop adding your own narration on top.', '{"perspective","clarity"}', '{"reality vs. illusion","discernment","foundational clear thinking"}', 'When you need to cut through noise to find signal -- in decision-making, in conflict, in any moment where anxiety is manufacturing false realities.', 'A', 'The philosophical bedrock of the entire Gita: learn to distinguish what is truly real from what is merely appearing. Every clear decision depends on this capacity.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (9, 2, 20, 'na jāyate mriyate vā kadācin nāyaṁ bhūtvā bhavitā vā na bhūyaḥ', 'He is not born nor does He ever die; after having been, He again ceases not to be. Unborn, eternal, changeless and ancient, He is not killed when the body is killed.', 'You are not your job title. You are not your bank balance. You are not your body. Strip all of that away and something remains. Call it awareness, call it consciousness, call it whatever you want. The point is: the thing that''s reading these words right now can''t be fired, can''t get sick, and can''t be diminished by anything that happens to you. That''s worth knowing on a bad day.', 'Write down three things about yourself that can''t be taken away by a layoff, a breakup, or a diagnosis.', 'If everything external were stripped away tomorrow, what would still be true about you?', 'You are not your body and hair-style, but you are will; and if your will beautiful, then you will be beautiful.', 'Epictetus, Discourses, 3.1.40', 'Both the Gita and Epictetus relocate identity from the perishable exterior to the permanent interior. You are not your attributes. You are your agency.', '{"perspective","acceptance"}', '{"identity beyond circumstance","indestructible self","freedom from external identity"}', 'After a job loss, a breakup, a health diagnosis, or any event that strips away a layer of who you thought you were.', 'C', 'You are not your job title, your bank balance, or your body. This verse locates identity in something that cannot be taken away -- a radical reframe for anyone whose sense of self is externally anchored.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (10, 2, 22, 'vāsāṁsi jīrṇāni yathā vihāya navāni gṛhṇāti naro ''parāṇi', 'Just as a man casts off worn-out clothes and puts on new ones, so also the embodied Self casts off worn-out bodies and enters others that are new.', 'Change isn''t happening to you. Change is how everything works. That career you outgrew, that relationship that ended, that version of yourself you can''t recognize anymore. You didn''t fail those things. You just changed clothes.', 'Think of one thing from your past that felt like a devastating ending. Notice how it turned out to be a door.', 'What are you holding onto right now that you''ve already outgrown?', 'Both the substances themselves, we see as a flood, are in a continual flux; and all actions in a perpetual change; and the causes themselves, subject to a thousand alterations, neither is there anything almost, that may ever be said to be now settled and constant.', 'Marcus Aurelius, Meditations, 5.23', 'Both the Gita and Marcus see change not as a disruption of life but as the basic operating principle of everything that exists.', '{"acceptance","perspective"}', '{"change as renewal","life transitions","naturalness of transformation"}', 'During any major life transition -- starting a new career, ending a relationship, moving cities, entering a new decade of life.', 'A', 'The garment metaphor makes change feel natural rather than catastrophic. Career pivots, identity shifts, and life transitions are not endings -- they are wardrobe changes.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (11, 2, 31, 'sva-dharmam api cāvekṣya na vikampitum arhasi', 'Further, having regard to thy own duty, thou shouldst not waver, for there is nothing higher for a Kshatriya than a righteous war.', 'You know what you need to do. You''ve known for a while. The problem isn''t information. It''s nerve. Every day you spend ''thinking about it'' is a day you''re choosing hesitation over the thing that''s clearly yours to do.', 'Name the thing you''ve been putting off. Write down exactly one next step. Do that step before lunch.', 'What decision have you already made in your gut that your mind keeps pretending is still open?', 'It''s not at all that we have too short a time to live, but that we squander a great deal of it.', 'Seneca, On the Brevity of Life, 1.3-4a', 'Both Krishna and Seneca say the same thing: you have enough time. You''re just spending it on hesitation.', '{"courage","clarity"}', '{"duty aligned with purpose","decisiveness","ending hesitation"}', 'When you know what you should do but keep finding reasons to delay. When the alignment between duty and purpose is clear but your nerve fails.', 'B', 'When your purpose aligns with what needs doing, hesitation becomes self-sabotage. This verse strips away Arjuna''s philosophical hand-wringing and names the real problem: he is wavering from what he knows is his to do.', true, false, 'source: On the Brevity of Life (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (12, 2, 38, 'sukha-duḥkhe same kṛtvā lābhālābhau jayājayau', 'Having made pleasure and pain, gain and loss, victory and defeat the same, engage thou in battle for the sake of battle; thus thou shalt not incur sin.', 'Do the thing because the thing needs doing, not because you''ll get praised for it. Before the meeting, the pitch, the hard conversation, find your center. The outcome isn''t yours to control. The quality of your engagement is.', 'Before your next stressful event today, take three slow breaths and remind yourself: I control how I show up. I don''t control what happens next.', 'What would you do differently today if you genuinely didn''t care whether you won or lost?', 'Keep in mind that it isn''t the one who has it in for you and takes a swipe that harms you, but rather the harm comes from your own belief about the abuse. So when someone arouses your anger, know that it''s really your own opinion fueling it.', 'Epictetus, Enchiridion, 20', 'Both Krishna and Epictetus locate the source of suffering in the same place: not in what happens to you, but in what you believe about what happens to you.', '{"discipline","acceptance"}', '{"equanimity in action","acting from center","non-reactivity"}', 'Before any high-stakes negotiation, confrontation, or performance -- the instruction to center yourself before you engage.', 'B', 'Act from equanimity, not from emotional reactivity. This is not suppression of feeling -- it is the instruction to find a stable center before engaging with anything consequential.', true, false, 'Enchiridion text not available in public domain source files; quote sourced from modern translation.');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (13, 2, 47, 'karmaṇy evādhikāras te mā phaleṣu kadācana', 'Thy right is to work only, but never with its fruits; let not the fruits of actions be thy motive, nor let thy attachment be to inaction.', 'This is probably the most famous verse in the Gita, and it''s famous because it solves about half of your problems in one line. You get to do the work. You don''t get to control the results. The second you start working for the outcome instead of the work itself, you''ve lost the thread.', 'Pick one thing you''ve been agonizing over today. Do the part that''s yours. Then put it down.', 'What are you holding onto right now that was never yours to carry?', 'Externals are not in my power: will is in my power. Where shall I seek the good and the bad? Within, in the things which are my own.', 'Epictetus, Discourses, 2.5.4-5', 'Both the Gita and Epictetus draw the same line: your jurisdiction ends at the action itself, and everything beyond that belongs to forces outside your control.', '{"discipline","clarity"}', '{"detachment from outcomes","right to action alone","freedom from results-anxiety"}', 'Before any launch, submission, or performance where the outcome is uncertain -- the anxiety of ''will it work?'' vs. ''am I doing the right thing?''', 'A', 'The single most famous verse of the Gita and arguably the most universally applicable piece of wisdom in Indian philosophy. The antidote to both perfectionism and procrastination in one line.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (14, 2, 48, 'yoga-sthaḥ kuru karmāṇi saṅgaṁ tyaktvā dhanañjaya', 'Perform action, O Arjuna, being steadfast in Yoga, abandoning attachment and balanced in success and failure! Evenness of mind is called Yoga.', 'Do the work. Drop the scoreboard. This isn''t about being indifferent to quality. It''s about not letting your mood swing with every win and loss. The athlete who checks the score every thirty seconds plays worse than the one who''s just playing.', 'For the next two hours, work without checking any metrics, likes, or feedback. Just do the work.', 'Where are you keeping score so obsessively that it''s actually hurting your performance?', 'Others again there be, who when they have done any such thing, do not so much as know what they have done; but are like unto the vine, which beareth her grapes, and when once she hath borne her own proper fruit, is contented and seeks for no further recompense.', 'Marcus Aurelius, Meditations, 5.6', 'Both the Gita and Marcus use the same image: the vine doesn''t demand applause after bearing fruit. It just gets on with the next season.', '{"discipline","acceptance"}', '{"flow state","detached engagement","equanimity in success and failure"}', 'In the middle of a long project where results are far off -- when you need to find meaning in the daily work itself, not in the eventual outcome.', 'A', 'The operational companion to 2.47: do the work, drop the scoreboard. This is the athlete''s flow state, the entrepreneur''s only sane operating mode, and the artist''s path to their best work.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (15, 2, 50, 'buddhi-yukto jahātīha ubhe sukṛta-duṣkṛte', 'Endowed with wisdom (evenness of mind), one casts off in this life both good and evil deeds; therefore, devote thyself to Yoga; Yoga is skill in action.', '''Yoga is skill in action.'' Three words that redefine what mastery means. It''s not about what you achieve. It''s about how you engage. The barista who''s fully present while making your coffee is closer to this than the CEO checking email during a board meeting.', 'Take your most boring task today and do it with total attention. Not because it deserves it, but because you do.', 'Where in your life are you performing with skill but without any presence?', 'The true joy of a man, is to do that which properly belongs unto a man.', 'Marcus Aurelius, Meditations, 8.26', 'Both the Gita and Marcus define the highest human achievement the same way: not results, but the quality of how you show up to the work.', '{"discipline","clarity"}', '{"skill in action","mastery through engagement","process over outcome"}', 'When you feel that what you are doing is too small or mundane to matter -- the reminder that excellence lives in the how, not the what.', 'B', '''Yoga is skill in action'' -- three words that redefine mastery. It is not about what you achieve but about the quality of how you engage. This makes excellence accessible to anyone in any circumstance.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (16, 2, 55, 'prajahāti yadā kāmān sarvān pārtha mano-gatān', 'When a man completely casts off, O Arjuna, all the desires of the mind and is satisfied in the Self by the Self, then is he said to be one of steady wisdom!', 'Real contentment isn''t about getting everything on the list. It''s about the moment you stop writing the list. You already have a version of everything you need. The gap between ''what I have'' and ''what I want'' is where most of your suffering lives.', 'Look around the room you''re in right now. Name three things you''d desperately miss if they were gone. You already have those.', 'What if the problem isn''t that you don''t have enough, but that you''ve never paused long enough to notice that you do?', 'To have whatsoever he wishes is in no man''s power; it is in his power not to wish for what he has not, but cheerfully to employ what comes to him.', 'Seneca, Moral Letters, 123.3', 'Both Krishna and Seneca define contentment the same way: not getting everything you want, but cheerfully employing what''s already in front of you.', '{"clarity","acceptance"}', '{"inner contentment","desirelessness","self-sufficiency"}', 'When the next purchase, promotion, or achievement fails to deliver lasting satisfaction. When you suspect that the problem is not what you have but how you relate to wanting.', 'B', 'True contentment comes from within, not from accumulating more. When a person casts off all desires within the mind and is content in the self by the self, that is the beginning of real peace -- not the absence of desire but the absence of being driven by it.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (17, 2, 56, 'duḥkheṣv anudvigna-manāḥ sukheṣu vigata-spṛhaḥ', 'He whose mind is not shaken by adversity, who does not hanker after pleasures, and who is free from attachment, fear and anger, is called a sage of steady wisdom.', 'Here''s a checklist for how you''re actually doing, and it''s not about what you''ve accomplished. When things go wrong, does your mind stay steady? When something shiny shows up, do you lose your grip? Are fear and anger running your decisions? Be honest.', 'Right now, run a quick inner scan. On a scale of 1-10, how steady is your mind? Not happy. Steady. That''s the metric that matters.', 'Which of these three has the most power over you right now: craving, fear, or anger?', 'Who then is the invincible? It is he whom none of the things disturb which are independent of the will.', 'Epictetus, Discourses, 1.18.21', 'Both the Gita and Epictetus define strength the same way: not by what you can do, but by what can''t knock you off center.', '{"patience","discipline"}', '{"emotional mastery","steadiness of mind","freedom from reactivity"}', 'As a daily self-assessment tool: Am I undisturbed in sorrow today? Am I craving? Am I reactive? A mirror for the inner life.', 'A', 'The most precise character portrait of emotional mastery in the Gita -- undisturbed in sorrow, free from craving, beyond passion, fear, and anger. Specific, measurable, and aspirational without being preachy.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (18, 2, 62, 'dhyāyato viṣayān puṁsaḥ saṅgas teṣūpajāyate', 'When a man thinks of the objects, attachment to them arises; from attachment desire is born; from desire anger arises.', 'This is the most precise map of a downward spiral ever drawn, and it''s 2,500 years old. Thinking becomes attachment. Attachment becomes craving. Craving becomes anger when you can''t have it. And once anger takes over, your judgment is gone. It''s the blueprint for every doom-scroll and every 2 AM argument with someone who isn''t in the room.', 'Notice the next time you pick up your phone without a reason. That''s step one of the spiral. Just noticing it breaks the chain.', 'What thought have you been returning to obsessively this week, and where is it taking you?', 'Every habit and faculty is maintained and increased by the corresponding actions: the habit of walking by walking, the habit of running by running. If you would make anything a habit, do it; if you would not make it a habit, do not do it, but accustom yourself to do something else in place of it.', 'Epictetus, Discourses, 2.18.1-5', 'Both the Gita and Epictetus show how mental patterns compound: the spiral goes one direction or the other, and the direction is set by what you keep practicing.', '{"clarity","discipline"}', '{"the downward spiral","rumination","how poor decisions cascade"}', 'When you notice yourself spiraling -- checking social media compulsively, ruminating on a slight, binge-consuming anything. The diagnostic that names the disease.', 'A', 'The ''downward spiral'' mapped with clinical precision -- from rumination to attachment to desire to anger to confusion to the destruction of intelligence. Directly applicable to doom-scrolling, comparison traps, and addictive loops.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (19, 2, 64, 'rāga-dveṣa-vimuktais tu viṣayān indriyaiś caran', 'But the self-controlled man, moving amongst objects with the senses under restraint, and free from attraction and repulsion, attains to peace.', 'You don''t have to avoid the world to be at peace in it. The point isn''t to stop feeling attraction or aversion. It''s to stop letting those feelings make your decisions. You can walk through a bakery without buying everything. That''s what self-control actually looks like.', 'The next time you feel a strong pull toward something today, pause for five seconds. Don''t fight it. Just insert a gap between the impulse and the action.', 'What''s one thing you keep saying yes to automatically that you''d be better off pausing before?', 'Whenever you get an impression of some pleasure, as with any impression, guard yourself from being carried away by it, let it await your action, give yourself a pause.', 'Epictetus, Enchiridion, 34', 'Both Krishna and Epictetus teach the same skill: don''t fight the feeling. Just insert a pause between the impulse and the action.', '{"discipline","patience"}', '{"middle path","engaged composure","freedom from reactivity"}', 'When you notice yourself bouncing between craving and avoidance. When you want to engage with life fully without being puppeted by every stimulus.', 'B', 'You can engage fully with the world while maintaining inner composure. This is not withdrawal but mastery -- moving through life with senses under control, free from the pendulum of attraction and aversion, and arriving at serenity.', true, false, 'Enchiridion text not available in public domain source files; quote sourced from modern translation.');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (20, 2, 70, 'āpūryamāṇam acala-pratiṣṭhaṁ samudram āpaḥ praviśanti yadvat', 'He attains peace into whom all desires enter as waters enter the ocean, which, filled from all sides, remains unmoved; but not the man who is full of desires.', 'Think about the ocean. Rivers pour into it constantly, and it doesn''t overflow or panic. That''s the model. Not blocking desires and distractions, but being large enough to absorb them without being moved. Your inbox, your notifications, your cravings. Let them arrive. You don''t have to react to everything that shows up.', 'For the next hour, let every notification arrive without immediately responding. Be the ocean, not the puddle.', 'What would it feel like to let things come to you without needing to react to all of them?', 'It will but little avail thee, to turn thine anger and indignation upon the things themselves that have fallen cross unto thee. For as for them, they are not sensible of it.', 'Marcus Aurelius, Meditations, 7.38', 'Both the Gita and Marcus point out the same thing: the stuff that''s bothering you isn''t even aware that it''s bothering you. Be large enough to absorb the impact.', '{"patience","acceptance"}', '{"absorptive capacity","peace amid stimulus","the ocean mind"}', 'In any environment of constant stimulation -- open offices, social media feeds, demanding relationships -- when you need the image of something that receives everything and remains still.', 'B', 'The ocean metaphor: desires and stimuli never stop arriving, but peace comes from being large enough to absorb them without being moved. Not blocking, not indulging -- absorbing.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (21, 3, 4, 'na karmaṇām anārambhān naiṣkarmyaṁ puruṣo ''śnute', 'Not by the non-performance of actions does man reach actionlessness, nor by mere renunciation does he attain to perfection.', 'You can''t think your way to transformation. At some point, the reading, the planning, the researching becomes a very sophisticated way of avoiding the work. You don''t achieve anything by not doing things. You especially don''t achieve freedom by sitting still and calling it enlightenment.', 'What''s the one thing you''ve been ''learning about'' instead of actually doing? Take the smallest possible action on it right now.', 'Is there something you''ve turned into a permanent research project to avoid the discomfort of actually starting?', 'Spend not the remnant of thy days in thoughts and fancies concerning other men, when it is not in relation to some common good, when by it thou art hindered from some other better work.', 'Marcus Aurelius, Meditations, 3.14', 'Both the Gita and Marcus deliver the same rebuke to the eternal student: stop spending your days on thoughts and fancies when the actual work is waiting.', '{"courage","discipline"}', '{"action over withdrawal","freedom through engagement","anti-escapism"}', 'When you have read enough books, attended enough workshops, and consumed enough content -- and still have not started the thing you know you need to do.', 'A', 'You cannot think your way to transformation -- you have to act. Withdrawal and endless analysis are not enlightenment; they are sophisticated forms of avoidance.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (22, 3, 5, 'na hi kaścit kṣaṇam api jātu tiṣṭhaty akarma-kṛt', 'Verily none can ever remain for even a moment without performing action; for, everyone is made to act helplessly indeed by the qualities born of Nature.', 'You can''t not act. Even sitting on the couch scrolling your phone is an action. Even ''keeping your options open'' is a choice with consequences. The idea that you can stay neutral, avoid commitment, and wait for the perfect moment? That''s not patience. That''s a decision to let things happen to you instead of choosing what happens next.', 'Name one thing you''ve been ''putting off deciding.'' Recognize: you already decided by not deciding. Now make a real choice.', 'Where are you pretending to be neutral when you''ve actually already chosen by default?', 'No act is honourable that is done by an unwilling agent, that is compulsory. Every honourable act is voluntary.', 'Seneca, Moral Letters, 66.16b', 'Both Krishna and Seneca dissolve the illusion of passivity: since you must act anyway, the real question is whether you act consciously or get dragged along unconsciously.', '{"perspective","clarity"}', '{"no neutral position","inaction as action","compulsory engagement"}', 'When you tell yourself you are ''keeping your options open'' or ''waiting to decide'' -- the reminder that not-deciding is already a decision with real costs.', 'C', 'Inaction is itself an action. Even ''doing nothing'' is a choice with consequences. This verse removes the illusion of a neutral position -- you are always choosing, whether you acknowledge it or not.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (23, 3, 7, 'yas tv indriyāṇi manasā niyamyārabhate ''rjuna', 'But whosoever, controlling the senses by the mind, O Arjuna, engages himself in Karma Yoga with the organs of action, without attachment, he excels!', 'The person who stays engaged with the world but keeps their inner compass steady beats the person who just checks out. Withdrawing from everything isn''t strength. Showing up fully present, without getting dragged around by every desire? That''s the harder and more valuable move.', 'Do one thing you''d normally avoid today, but do it without complaining internally. That''s the practice.', 'Are you confusing checking out with inner peace?', 'Were all the geniuses of history to focus on this single theme, they could never fully express their bafflement at the darkness of the human mind. No person would give up even an inch of their estate, and the slightest dispute with a neighbor can mean hell to pay; yet we easily let others encroach on our lives.', 'Seneca, On the Brevity of Life, 3.1-2', 'Both Krishna and Seneca find it baffling how freely people surrender their time and attention while guarding everything else.', '{"discipline","courage"}', '{"engaged action","detached performance","superiority of practice over withdrawal"}', 'When you confuse spiritual growth with checking out. When you need to remember that controlled engagement with the world is harder and more valuable than retreat.', 'B', 'The person who acts with deliberate engagement and emotional detachment outperforms the person who merely abstains. This verse destroys the myth that spirituality means withdrawal -- the engaged practitioner excels over the recluse.', true, false, 'source: On the Brevity of Life (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (24, 3, 19, 'tasmād asaktaḥ satataṁ kāryaṁ karma samācara', 'Therefore, without attachment, do thou always perform action which should be done; for, by performing action without attachment man reaches the Supreme.', 'Show up. Do the work. Let go of the result. Repeat. Every day. That''s it. This isn''t some elevated spiritual state. It''s an operating instruction for anyone who has a practice, a job, or a life they''re trying to build. Motivation is nice when it shows up. It''s not required.', 'Do the most important thing on your list today without checking how it''s received. Ship it and move on.', 'If no one ever saw or acknowledged your work, would you still do it?', 'Be it all one unto thee, whether half frozen or well warm; whether only slumbering, or after a full sleep; whether discommended or commended thou do thy duty.', 'Marcus Aurelius, Meditations, 6.2', 'Both the Gita and Marcus say the same thing: do your duty whether you''re cold, warm, praised, or criticized. The conditions don''t get a vote.', '{"discipline","patience"}', '{"daily practice","consistent action","release of outcomes"}', 'For anyone building a practice -- creative, athletic, spiritual, professional -- the verse to return to every morning when motivation is absent and only discipline remains.', 'A', 'The daily practice distilled to its essence: show up, do the work, release the outcome. Every single day. This is not a philosophy -- it is an operating instruction.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (25, 3, 21, 'yad yad ācarati śreṣṭhas tat tad evetaro janaḥ', 'Whatsoever a great man does, that other men also do; whatever he sets up as the standard, that the world follows.', 'People don''t follow your advice. They follow your behavior. Your kids don''t do what you tell them. They do what you do. Your team doesn''t care about the values on the wall. They care about the values you demonstrate on a Tuesday afternoon when things go sideways.', 'Think about one habit you want someone in your life to adopt. Now check: are you modeling it yourself?', 'If someone watched how you actually spend your time this week, what would they conclude your real priorities are?', 'Whatsoever any man either doth or saith, thou must be good; not for any man''s sake, but for thine own nature''s sake; as if either gold, or the emerald, or purple, should ever be saying to themselves, Whatsoever any man either doth or saith, I must still be an emerald, and I must keep my colour.', 'Marcus Aurelius, Meditations, 7.15', 'Both the Gita and Marcus say the same thing: be the emerald. Your job is to show your true colors regardless of what anyone else does.', '{"courage","perspective"}', '{"leadership by example","behavioral influence","responsibility of the visible"}', 'When you realize people are watching and modeling your behavior -- as a parent, manager, elder sibling, or public figure.', 'B', 'Leadership is behavior, not title. Your actions set the template for everyone watching -- your children, your team, your community. The accountability is total and the leverage is enormous.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (26, 3, 27, 'prakṛteḥ kriyamāṇāni guṇaiḥ karmāṇi sarvaśaḥ', 'All actions are wrought in all cases by the qualities of Nature only. He whose mind is deluded by egoism thinks: ''I am the doer''.', 'That big success you had? You worked hard, sure. But also: timing, luck, your parents, the economy, the person who introduced you, and about a thousand other things you had nothing to do with. Same goes for your failures. Taking full personal credit or blame for anything is just ego pretending it''s running the show.', 'Think of your biggest recent win. Write down three things that contributed to it that had nothing to do with you.', 'Where are you taking too much credit or too much blame?', 'Consider the whole universe whereof thou art but a very little part, and the whole age of the world together, whereof but a short and very momentary portion is allotted unto thee.', 'Marcus Aurelius, Meditations, 5.24', 'Both the Gita and Marcus use the vastness of the universe to shrink the ego. You''re a participant in something enormous, not its sole author.', '{"perspective","acceptance"}', '{"ego dissolution","beyond doership","humility before complexity"}', 'After a big win (to prevent arrogance) or a devastating loss (to prevent self-destruction) -- any time you are tempted to take full personal credit or blame.', 'B', 'You are not the sole cause of your successes or your failures. Circumstance, timing, genetics, and a thousand unseen forces are always at work. This dissolves both arrogance and self-blame in a single stroke.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (27, 3, 34, 'indriyasyendriyasyārthe rāga-dveṣau vyavasthitau', 'Attachment and aversion for the objects of the senses abide in the senses; let none come under their sway, for they are his foes.', 'Your cravings aren''t you. Neither are your aversions. They live in your nervous system, and they''ll fire whether you want them to or not. The ice cream aisle will always call. The difficult email will always spike your heart rate. That''s fine. You just don''t have to obey.', 'Next time a craving hits, say to yourself: ''That''s a signal, not a command.'' Then wait 30 seconds.', 'What impulse have you been treating as part of your identity when it''s really just a pattern?', 'If thou canst but withdraw conceit and opinion concerning that which may seem hurtful and offensive, thou thyself art as safe, as safe may be.', 'Marcus Aurelius, Meditations, 8.47', 'Both the Gita and Marcus say the same thing: withdraw your opinion about the thing, and the thing loses its power over you.', '{"clarity","discipline"}', '{"cravings as mechanism","observer vs. impulse","freedom through awareness"}', 'When a craving feels like a command rather than a suggestion. When you need to remember that the pull you feel is a sensory event, not an identity.', 'B', 'Cravings and aversions are built into your nervous system; they are not ''you.'' The verse locates attraction and repulsion in the senses themselves, not in the self -- which means you can observe them without obeying them.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (28, 3, 35, 'śreyān sva-dharmo viguṇaḥ para-dharmāt sv-anuṣṭhitāt', 'Better is one''s own duty, though devoid of merit, than the duty of another well discharged. Better is death in one''s own duty; the duty of another is fraught with fear.', 'Your messy, imperfect, genuine path is better than a flawless imitation of someone else''s. This is the antidote to scrolling through other people''s highlight reels and feeling like you''re falling behind. You''re not behind. You''re in a different lane.', 'Notice the next time you compare yourself to someone today. Then ask: would I actually want their entire life, not just the part I''m envying?', 'What would you be doing right now if you''d never seen anyone else''s version of success?', 'Remember that you are an actor in a play, playing a character according to the will of the playwright. If he wishes you to play the beggar, play even that role well. For this is your duty, to perform well the character assigned you.', 'Epictetus, Enchiridion, 17', 'Both the Gita and Epictetus say fulfillment comes from playing your own role well, not from wishing you''d been cast in someone else''s.', '{"clarity","courage"}', '{"authenticity over imitation","svadharma","your path vs. theirs"}', 'When scrolling through others'' highlight reels, when envying a colleague''s trajectory, when tempted to abandon your own path for a more glamorous one.', 'A', 'Stop comparing your path to someone else''s. Your imperfect authentic work beats someone else''s polished template. This verse is the antidote to impostor syndrome and comparison culture.', true, false, 'Enchiridion text not available in public domain source files; quote sourced from modern translation.');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (29, 3, 37, 'kāma eṣa krodha eṣa rajo-guṇa-samudbhavaḥ', 'It is desire, it is anger born of the quality of Rajas, all-sinful and all-devouring; know this as the foe here (in this world).', 'Krishna names the enemy, and it''s not who you think. It''s not your boss, your ex, or the economy. It''s desire and its frustrated twin, anger. When you want something and can''t have it, the wanting curdles into rage. That''s the whole mechanism. Every time you''re furious, look underneath. There''s a desire that didn''t get met.', 'The next time you feel angry today, pause and ask: what did I want that I didn''t get? Name the desire underneath the anger.', 'What desire are you carrying right now that, if you examined it honestly, is the real source of your frustration?', 'There is no more stupefying thing than anger, nothing more bent on its own strength. If successful, none more arrogant, if foiled, none more insane.', 'Seneca, On Anger, 3.1.5', 'Both Krishna and Seneca name anger as the great self-destroyer. It''s not an external attack. It''s an internal fire that consumes the person who harbors it.', '{"clarity","discipline"}', '{"desire as enemy","anger as frustrated desire","root cause analysis"}', 'When you find yourself consistently angry or frustrated and cannot identify why -- the verse that points the flashlight inward at unexamined desire.', 'C', 'Unexamined desire and its frustrated twin -- anger -- are identified as the root enemy. Not external circumstances, not other people: desire and anger. A ruthlessly clear diagnostic.', true, false, 'source: On Anger (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (30, 4, 18, 'karmaṇy akarma yaḥ paśyed akarmaṇi ca karma yaḥ', 'He who seeth inaction in action and action in inaction, he is wise among men; he is a Yogi and performer of all actions.', 'The busiest person in the room might be accomplishing nothing. The one sitting quietly might be doing the most important work of the day. Busyness isn''t productivity, and rest isn''t laziness. Sometimes the wisest action is to stop.', 'Block 20 minutes of ''nothing'' on your calendar today. No phone, no tasks. Just sit. See what happens.', 'Where in your life are you confusing being busy with making progress?', 'The mind must be given relaxation. It will rise improved and sharper after a good break. Just as rich fields must not be forced, for they will quickly lose their fertility if never given a break.', 'Seneca, On Tranquility of Mind, 17.5', 'Both the Gita and Seneca challenge the cult of busyness: real wisdom knows when stillness is more productive than motion.', '{"clarity","perspective"}', '{"action in inaction","true productivity","wisdom beyond busyness"}', 'When you are filling every hour with activity but nothing meaningful is moving forward -- or when you feel guilty for resting, pausing, or saying no.', 'B', 'The deepest insight into effort: sometimes the busiest person accomplishes nothing, and sometimes stillness is the most powerful act. This verse rewires how you think about productivity.', true, false, 'source: On Tranquility of Mind (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (31, 4, 19, 'yasya sarve samārambhāḥ kāma-saṅkalpa-varjitāḥ', 'He whose undertakings are all devoid of desires and (selfish) purposes, and whose actions have been burnt by the fire of knowledge, him the wise call a sage.', 'When you strip away the self-interest from your work, something interesting happens. The quality goes up, not down. You''re not performing for applause or angling for advantage. You''re just doing what needs doing, cleanly, and moving on. The people who operate this way tend to be both the most effective and the most at peace.', 'Do one genuinely kind thing today that no one will ever know about. Not for karma. Just because you can.', 'If you removed the need for recognition from your work, what would change about how you do it?', 'Wherever there is a human being, there is an opportunity for kindness.', 'Seneca, On the Happy Life, 24.3', 'Both the Gita and Seneca describe the same liberated actor: someone whose actions arise from wisdom and goodness rather than from wanting something back.', '{"clarity","acceptance"}', '{"purified motivation","action without desire","inner freedom while active"}', 'When you are doing the right things but for the wrong reasons. When ambition has curdled into anxiety and you need to purify your motivation without abandoning your work.', 'B', 'Freedom is not about what you do but what drives you. A sage whose every undertaking is free from desire and whose actions are burned in the fire of knowledge can do great things without inner turmoil. The point is the quality of motivation, not the quantity of action.', true, false, 'source: On the Happy Life (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (32, 4, 38, 'na hi jñānena sadṛśaṁ pavitram iha vidyate', 'Verily there is no purifier in this world like knowledge. He who is perfected in Yoga finds it in the Self in time.', 'Two words in this verse change everything: ''in time.'' Not instantly. Not after one retreat. In time. The knowledge that actually transforms you isn''t the kind you consume. It''s the kind that arrives slowly, through experience, and often through failure. You probably already have insights you won''t fully understand for another five years. That''s fine. They''re ripening.', 'Think of one lesson you learned the hard way. Notice that no book could have taught it to you. Honor that.', 'What are you trying to learn through reading that you can only learn through doing?', 'He that knoweth not what the world is, knoweth not where he himself is. And he that knoweth not what the world was made for, cannot possibly know either what are the qualities, or what is the nature of the world.', 'Marcus Aurelius, Meditations, 8.52', 'Both the Gita and Marcus affirm that real knowledge is self-discovered and takes time. You can''t rush it any more than you can rush a season.', '{"patience","clarity"}', '{"self-discovered wisdom","patience in learning","knowledge as purification"}', 'For the person who feels behind, who watches others ''get it'' faster -- the promise that genuine understanding arrives on its own schedule and is worth the wait.', 'C', 'True knowledge is self-discovered, not consumed. And the emphasis on ''in time'' validates the slow learner, the late bloomer, the person who needs years to arrive at insight everyone else seems to grasp instantly.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (33, 4, 42, 'tasmād ajñāna-sambhūtaṁ hṛt-sthaṁ jñānāsinātmanaḥ', 'Therefore, with the sword of knowledge (of the Self) cut asunder the doubt of the self born of ignorance, residing in thy heart, and take refuge in Yoga; arise, O Arjuna!', 'You''ve done the research. You''ve gathered the opinions. You''ve thought about it from every angle. Now cut through it. The doubt that''s left isn''t wisdom. It''s a habit. At some point, deliberation is just procrastination wearing a suit.', 'That decision you''ve been sitting on? Make it in the next five minutes. Not perfectly. Just make it.', 'What doubt are you keeping alive because making a decision would mean you have to actually do something?', 'But life is not worth living, and there is no limit to our sorrows, if we indulge our fears to the greatest possible extent.', 'Seneca, Moral Letters, 13.12b', 'Both the Gita and Seneca deliver the same ultimatum: at some point, continued deliberation is just fear with a better vocabulary.', '{"courage","clarity"}', '{"decisiveness","cutting through doubt","arising to action"}', 'The moment of decision after analysis paralysis -- when the research is done, the counsel is gathered, and the only thing left is to move.', 'A', 'A battle cry for decisiveness: cut through doubt with the sword of knowledge and move. When you have deliberated enough, the remaining obstacle is not ignorance -- it is the habit of hesitation.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (34, 5, 3, 'jñeyaḥ sa nitya-sannyāsī yo na dveṣṭi na kāṅkṣati', 'He should be known as a perpetual Sannyasin who neither hates nor desires; for, free from the pairs of opposites, O mighty-armed Arjuna, he is easily set free from bondage!', 'True detachment isn''t living in a cave. It''s living a normal life without the whiplash of wanting and hating. You can have a career, a family, a full social calendar, and still be free. Freedom isn''t about what you do. It''s about whether craving and aversion are making your decisions for you.', 'Right now, notice one thing you already have that future-you would desperately miss. Sit with that for ten seconds.', 'What would your day look like if you genuinely didn''t hate or crave anything in it?', 'Fancy not to thyself things future, as though they were present but of those that are present, take some aside, that thou takest most benefit of, and consider of them particularly, how wonderfully thou wouldst want them, if they were not present.', 'Marcus Aurelius, Meditations, 7.27', 'Both the Gita and Marcus define freedom the same way: not having more, but wanting differently. Appreciate what''s here instead of chasing what isn''t.', '{"acceptance","discipline"}', '{"renunciation within engagement","freedom from dualities","active detachment"}', 'For the householder, the parent, the person with obligations who wonders whether spiritual freedom requires giving up their life -- it does not.', 'C', 'True renunciation is not giving things up -- it is being free from compulsive attraction and aversion while staying fully in the game. This redefines detachment for people who cannot and should not withdraw from life.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (35, 5, 10, 'brahmaṇy ādhāya karmāṇi saṅgaṁ tyaktvā karoti yaḥ', 'He who performs actions, offering them to Brahman and abandoning attachment, is not tainted by sin as a lotus leaf by water.', 'The lotus grows in the mud but nothing sticks to it. That''s the model. You don''t need a clean environment to stay clean. You need the right relationship to the mess. Work in the chaos, help where it''s needed, get your hands dirty. Just don''t absorb it.', 'Think of one situation today where you''re likely to absorb someone else''s negativity. Decide in advance: picture the water sliding off the leaf.', 'What environment are you letting stain you that doesn''t have to?', 'Such as thy thoughts and ordinary cogitations are, such will thy mind be in time. For the soul doth as it were receive its tincture from the fancies, and imaginations.', 'Marcus Aurelius, Meditations, 8.51', 'Both the Gita''s lotus leaf and Marcus''s counsel to guard your thoughts describe the same inner discipline: your surroundings don''t determine your inner state. You do.', '{"acceptance","discipline"}', '{"lotus-leaf principle","integrity in chaos","non-contamination"}', 'When your environment is toxic but leaving is not an option. When you need to stay engaged without being stained by what surrounds you.', 'B', 'The lotus-leaf metaphor: fully engaged with the muddy world but nothing sticks. This is the Gita''s most elegant image for maintaining integrity in messy environments -- you do not need to leave the mud, just stop absorbing it.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (36, 5, 18, 'vidyā-vinaya-sampanne brāhmaṇe gavi hastini', 'Sages look with an equal eye on a Brahmin endowed with learning and humility, on a cow, on an elephant, and even on a dog and an outcaste.', 'The wise person sees the same essential reality in a professor and a stray dog. That sounds absurd until you think about it. Both are alive. Both experience pain. Both will die. The differences we obsess over, credentials, status, species, are real but they''re not the whole picture. Training yourself to see what''s shared is harder than cataloging what''s different. And it changes how you treat everyone.', 'The next person you interact with today, regardless of their status, look them in the eye and silently acknowledge: same stuff, different packaging.', 'Who do you unconsciously treat as less worthy of your attention, and what would shift if you stopped?', 'Ever consider and think upon the world as being but one living substance, and having but one soul, and how all things in the world, are terminated into one sensitive power; and are done by one general motion as it were, and deliberation of that one soul.', 'Marcus Aurelius, Meditations, 4.40', 'Both the Gita and Marcus see beneath surface differences to a single underlying reality connecting all beings.', '{"perspective","acceptance"}', '{"equal vision","shared humanity","non-judgment"}', 'When noticing yourself judging others by title, appearance, or background — a reminder that the person serving your coffee and the CEO share the same essential nature.', 'C', 'True wisdom dissolves arbitrary hierarchies — every person you encounter shares the same fundamental nature, regardless of surface differences.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (37, 5, 22, 'ye hi saṁsparśa-jā bhogā duḥkha-yonaya eva te', 'The enjoyments that are born of contacts are generators of pain only, for they have a beginning and an end, O Arjuna! The wise do not rejoice in them.', 'That thing you just bought? You''ll be bored with it in six weeks. That promotion you wanted? The thrill lasts about three days before the new anxiety kicks in. Pleasures that come from external contact have a built-in expiration date. The Gita isn''t saying don''t enjoy things. It''s saying don''t be surprised when the enjoyment fades. And definitely don''t build your life strategy around chasing the next hit.', 'Think of the last purchase that excited you. How long did the excitement last? Let the answer teach you something.', 'What are you currently chasing that you already know won''t satisfy you for more than a week?', 'Freedom is acquired not by the full possession of the things which are desired, but by removing the desire. And that you may know that this is true, as you have laboured for those things, so transfer your labour to these.', 'Epictetus, Discourses, 4.1.175', 'Both the Gita and Epictetus diagnose the same disease: pursuing more pleasure never satisfies because the problem was never insufficient pleasure. It was the structure of desire itself.', '{"perspective","patience"}', '{"hedonic treadmill","impermanence of pleasure","dissatisfaction cycle"}', 'When the promotion, the purchase, the vacation, or the achievement fails to deliver the lasting satisfaction it promised.', 'C', 'Hedonic adaptation explained in one verse. Pleasures born from sense-contact have a beginning and an end -- the pursuit of them is a treadmill whose endpoint is always dissatisfaction.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (38, 5, 23, 'śaknotīhaiva yaḥ soḍhuṁ prāk śarīra-vimokṣaṇāt', 'He who is able, while still here in this world to withstand, before the liberation from the body, the impulse born of desire and anger, he is a Yogi, he is a happy man.', 'Happiness isn''t the absence of difficult feelings. It''s the ability to withstand them without being wrecked. The person who can sit with desire without being dragged by it, and with anger without being consumed by it? That person is free in a way that has nothing to do with how their life looks from the outside.', 'The next time you feel a surge of anger or craving, try to sit with it for 60 seconds without acting on it. Just feel it. That''s the whole practice.', 'What internal storm are you trying to eliminate when you should be learning to weather it?', 'I should prefer to be free from torture; but if the time comes when it must be endured, I shall desire that I may conduct myself therein with bravery, honour, and courage.', 'Seneca, Moral Letters, 67.4', 'Both the Gita and Seneca redefine the good life: not the absence of difficulty, but the presence of the capacity to meet it without breaking.', '{"discipline","patience"}', '{"happiness as resilience","withstanding internal storms","redefining wellbeing"}', 'When you realize that removing all problems will not make you happy -- and that building the inner strength to handle them will.', 'A', 'Happiness is redefined as the capacity to withstand internal storms -- not the absence of them. This single reframe transforms the entire pursuit of wellbeing from accumulation to resilience.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (39, 6, 5, 'uddhared ātmanātmānaṁ nātmānam avasādayet', 'Let a man lift himself by his own Self alone; let him not lower himself, for this self alone is the friend of oneself and this self alone is the enemy of oneself.', 'No one is coming to save you. That''s not pessimism. That''s the beginning of actual power. You''re the only person who can pull yourself out of the ditch, and you''re the only person who can push yourself into one. That might be the most terrifying and liberating thing you''ll hear today.', 'Name one area where you''ve been waiting for someone else to fix things. Now name one tiny step you could take on it yourself. Take it.', 'In what part of your life are you waiting for rescue instead of rescuing yourself?', 'The material for the wise and good man is his own ruling faculty.', 'Epictetus, Discourses, 3.3.1', 'Both the Gita and Epictetus identify you as both the raw material and the craftsman. You are the project and the worker at the same time.', '{"courage","discipline"}', '{"self-rescue","self-sabotage","radical self-responsibility"}', 'When you realize no one is coming to save you -- and that this realization is not despair but the beginning of genuine power.', 'A', 'You are simultaneously your own rescuer and your own saboteur. No guru, no system, no partner holds that power -- only you. The most empowering and terrifying truth in the text.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (40, 6, 6, 'bandhur ātmātmanas tasya yenātmaivātmanā jitaḥ', 'The self is the friend of the self for him who has conquered himself by the Self, but to the unconquered self, this self stands in the position of an enemy like the (external) foe.', 'Your relationship with yourself sets the terms for every other relationship you''ll ever have. When your self-talk is destructive, you''re at war with the one person you can never get away from. When you''ve made peace with yourself, you''ve secured the only ally who''s guaranteed to show up every single day.', 'Catch the next negative thing you say to yourself and rephrase it the way you''d say it to a friend. Not cheerful. Just fair.', 'If your self-talk were a person, would you want them as a friend or would you cut them out of your life?', 'I have often wondered how it should come to pass, that every man loving himself best, should more regard other men''s opinions concerning himself than his own.', 'Marcus Aurelius, Meditations, 12.4', 'Both the Gita and Marcus point to the same paradox: we love ourselves above all others yet trust everyone else''s opinion of us more than our own.', '{"clarity","discipline"}', '{"the self as friend or enemy","self-mastery","inner alliance"}', 'When self-talk is destructive, when inner criticism is louder than any external voice -- the verse that names the internal relationship as the one that matters most.', 'A', 'Self-mastery converts your inner life from battleground to ally. The relationship you have with yourself is the one relationship that determines all others.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (41, 6, 7, 'jitātmanaḥ praśāntasya paramātmā samāhitaḥ', 'The Supreme Self of him who is self-controlled and peaceful is balanced in cold and heat, pleasure and pain, as also in honour and dishonour.', 'Once you stabilize internally, the outside world loses its power over you. Not because you''ve stopped feeling things, but because you''ve stopped letting them run the show. Cold, heat, praise, criticism. They still arrive. They just don''t get to choose your mood anymore. That''s not numbness. That''s the result of very specific inner work.', 'Pick one thing that reliably ruins your mood (traffic, a coworker, the news). Today, when it happens, notice: the event is neutral. Your reaction is the variable.', 'What external condition are you giving the most power over your inner state right now?', 'It is in thy power absolutely to exclude all manner of conceit and opinion, as concerning this matter; and by the same means, to exclude all grief and sorrow from thy soul. For as for the things and objects themselves, they of themselves have no such power, whereby to beget and force upon us any opinion at all.', 'Marcus Aurelius, Meditations, 6.52', 'Both Krishna and Marcus describe the same immunity: external conditions have no inherent power over your inner state. The power was always yours to give or withhold.', '{"patience","acceptance"}', '{"environmental immunity","inner stability","transcending conditions"}', 'When external conditions dominate your inner state. When weather, traffic, or someone''s tone of voice can ruin your entire day.', 'C', 'Environmental immunity: once you stabilize internally, external conditions lose their power over you. Cold and heat, pleasure and pain, honor and dishonor become equally unable to move the settled self.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (42, 6, 16, 'nāty-aśnatas tu yogo ''sti na caikāntam anaśnataḥ', 'Verily Yoga is not possible for him who eats too much, nor for him who does not eat at all; nor for him who sleeps too much, nor for him who is (always) awake, O Arjuna!', 'No extremes. Not too much food, not too little. Not too much sleep, not too little. The Gita is remarkably practical here. Before you worry about your meditation practice or your spiritual growth, ask yourself: did you eat well today? Did you sleep enough? The boring stuff isn''t the foundation for the real work. The boring stuff IS the real work.', 'Do a quick audit: on a scale of 1-10, how are you doing on sleep, food, and movement today? Fix the lowest one first.', 'Which basic need are you consistently neglecting in the name of productivity?', 'Set aside a certain number of days, during which you shall be content with the scantiest and cheapest fare, with coarse and rough dress, saying to yourself the while: ''Is this the condition that I feared?''', 'Seneca, Moral Letters, 18.5-6', 'Both the Gita and Seneca address the relationship between physical habits and mental capacity. Moderation isn''t boring. It''s the operating system everything else runs on.', '{"discipline","patience"}', '{"moderation","balance as foundation","no extremes"}', 'When your practice is failing and you cannot figure out why -- the answer is often in the basics: sleep, food, movement, rest.', 'C', 'Balance and moderation as prerequisites for any practice. The unglamorous truth that extremes in any direction -- eating, sleeping, working -- undermine everything else you are trying to build.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (43, 6, 17, 'yuktāhāra-vihārasya yukta-ceṣṭasya karmasu', 'Yoga becomes the destroyer of pain for him who is always moderate in eating and recreation (such as walking, etc.), who is moderate in exertion in actions, who is moderate in sleep and wakefulness.', 'Eat well. Sleep enough. Move your body. Don''t overwork. This sounds boring because it is. But most ''spiritual practices'' fail not because the person lacks willpower or enlightenment, but because they''re skipping meals, sleeping four hours, and wondering why they can''t focus. The basics aren''t the foundation. They''re the whole building.', 'Tonight, go to bed 30 minutes earlier than usual. That''s it. That''s the spiritual practice.', 'Which fundamental are you neglecting right now: sleep, food, movement, or rest?', 'It is not the man who has too little, but the man who craves more, that is poor.', 'Seneca, Moral Letters, 2.6', 'Both the Gita and Seneca insist on the same unglamorous truth: more isn''t better. Moderation in the basics is the foundation everything else is built on.', '{"discipline","patience"}', '{"fundamentals","regulated living","mundane foundations of excellence"}', 'When you are burning out because you have neglected sleep, food, or rest in pursuit of productivity. When the fundamentals need attention before anything else.', 'B', 'The mundane foundations of peak performance: regulated eating, recreation, sleeping, and waking. The Gita does not romanticize spiritual practice -- it insists on the boring fundamentals. Ancient biohacking without the marketing.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (44, 6, 25, 'śanaiḥ śanair uparamed buddhyā dhṛti-gṛhītayā', 'Little by little let him attain to quietude by the intellect held firmly; having made the mind establish itself in the Self, let him not think of anything.', 'Little by little. Three words that should be tattooed on the forehead of anyone who wants to change their life overnight. The Gita doesn''t promise a lightning bolt of transformation. It promises gradual progress through patient, steady effort. If you showed up today and tried a little harder than yesterday, that''s not mediocrity. That''s the method.', 'Whatever practice you''ve been trying to start (meditation, exercise, journaling), do it for two minutes today. Not twenty. Two.', 'Where are you all-or-nothing when you should be little-by-little?', 'Fancy not to thyself things future, as though they were present but of those that are present, take some aside, that thou takest most benefit of, and consider of them particularly, how wonderfully thou wouldst want them, if they were not present.', 'Marcus Aurelius, Meditations, 7.27', 'Both the Gita and Marcus insist that meaningful change is incremental. Contentment with small steps isn''t mediocrity. It''s wisdom.', '{"patience","discipline"}', '{"gradual progress","patience as method","step by step"}', 'When you are three weeks into a new practice and frustrated by the lack of dramatic results -- the ancient voice saying: this is exactly how it works.', 'C', 'Gradually, step by step. The instruction is explicit: do not rush. Patience is not a virtue supplementing the practice -- it IS the method. A direct rebuke to the culture of instant results.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (45, 6, 26, 'yato yato niścalati manaś cañcalam asthiram', 'From whatever cause the restless, unsteady mind wanders away, from that let him restrain it and bring it under the control of the Self alone.', 'Your mind wanders. You bring it back. That''s not the failure of meditation. That IS meditation. Every time you notice you''ve drifted and return to focus, you just did a rep. The person whose mind never wanders isn''t more advanced. They''re probably just not paying attention.', 'Set a timer for two minutes. Focus on your breath. When your mind wanders (it will), just bring it back. Each return is a successful rep.', 'Where else in your life do you confuse the practice with the failure?', 'This is the true athlete, the man who exercises himself against such appearances. Stay, wretch, do not be carried away. Great is the combat, divine is the work; it is for kingship, for freedom, for happiness, for freedom from perturbation.', 'Epictetus, Discourses, 2.18.27-28', 'Both the Gita and Epictetus frame mental discipline as an athletic event. The struggle isn''t a sign of failure. It''s the exercise through which mastery is built.', '{"discipline","patience"}', '{"meditation instruction","the wandering mind","returning as practice"}', 'For anyone who has tried meditation and concluded they are ''bad at it'' because their mind wanders -- the verse that says: the wandering IS normal, the returning IS the practice.', 'A', 'The foundational instruction of every meditation tradition: the mind wanders, you bring it back. That IS the practice. Not the failure of practice -- the practice itself.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (46, 6, 34, 'cañcalaṁ hi manaḥ kṛṣṇa pramāthi balavad dṛḍham', 'The mind verily is restless, turbulent, strong and unyielding, O Krishna! I deem it as difficult to control as to control the wind.', 'If it makes you feel any better, Arjuna was the greatest warrior of his generation and he said exactly what you''re thinking right now: ''I can''t control my own mind, and honestly, trying feels like trying to control the wind.'' You''re not uniquely bad at focus. Your mind is designed to wander. Everyone''s is.', 'The next time your mind races during an important task, don''t fight it. Just say ''I see you,'' and gently redirect. No judgment.', 'What if the difficulty of controlling your mind isn''t a personal failing but just the nature of having a mind?', 'Let it be thy earnest and incessant care to perform whatsoever it is that thou art about, with true and unfeigned gravity, natural affection, freedom and justice: and as for all other cares and imaginations, how thou mayest ease thy mind of them.', 'Marcus Aurelius, Meditations, 2.2', 'Both Arjuna and Marcus acknowledge the mind''s restlessness as universal. Both insist that acknowledging the difficulty is the first step, not an excuse to quit.', '{"patience","acceptance"}', '{"the restless mind","normalizing difficulty","validation of struggle"}', 'When you feel uniquely incapable of focus, discipline, or calm -- Arjuna, the greatest warrior, felt the same way. You are in good company.', 'B', 'The universal complaint voiced by Arjuna himself: the mind is restless, turbulent, and as hard to control as the wind. Validation that the difficulty of mental discipline is real and ancient, not a personal failing.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (47, 6, 35, 'asaṁśayaṁ mahā-bāho mano durnigrahaṁ calam', 'Undoubtedly, O mighty-armed Arjuna, the mind is difficult to control and restless; but, by practice and by dispassion it may be restrained!', 'Krishna doesn''t deny it. ''Yeah, the mind is hard to control. No question.'' But then comes the answer: practice and dispassion. Two levers. Practice means you keep showing up. Dispassion means you stop caring so much about the results of that practice. Both are learnable. Neither comes naturally.', 'Pick one small mental discipline you''ve abandoned (meditation, journaling, whatever). Do it for two minutes today. Just two.', 'What have you quit because it was hard, even though you knew the difficulty was the point?', 'But what is philosophizing? Is it not a preparation against events which may happen?', 'Epictetus, Discourses, 3.10.6-7', 'Both the Gita and Epictetus respond to ''this is too hard'' with the same honesty: of course it''s hard. What''s the alternative? The difficulty is the point.', '{"discipline","courage"}', '{"practice and dispassion","the answer to 'I can't'","two-lever solution"}', 'When you are ready to quit a practice, a discipline, a relationship -- the honest response that validates the difficulty while refusing to let you off the hook.', 'B', 'Krishna''s answer to ''I can''t do this'' is not denial but honest acknowledgment followed by the solution: practice and dispassion. Two levers, both required, both learnable.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (48, 6, 40, 'pārtha naiveha nāmutra vināśas tasya vidyate', 'O Arjuna, neither in this world, nor in the next world is there destruction for him; none, verily, who does good, O My son, ever comes to grief!', 'Every genuine effort counts. Nothing good you''ve done is wasted. That business that failed? The practice you abandoned? The relationship you poured yourself into that didn''t work? None of it was for nothing. The universe doesn''t punish sincerity. The effort went somewhere, even if you can''t see where yet.', 'Think of one ''failed'' effort from your past. Write down one thing it taught you or one way it changed you. That''s the proof it wasn''t wasted.', 'What effort have you been calling a failure that was actually just a long lesson?', 'A good man will do what he thinks it will be honourable for him to do, even if it involves toil; he will do it even if it involves harm to him; he will do it even if it involves peril.', 'Seneca, Moral Letters, 76.18', 'Both the Gita and Seneca promise the same thing: right action carries its own reward, regardless of visible results. The effort itself has value that can''t be erased.', '{"courage","acceptance"}', '{"no wasted effort","trust in the process","good faith is never lost"}', 'When a sincere effort has apparently failed -- a business that closed, a practice that stalled, a relationship that ended despite your best work.', 'C', 'Every genuine effort counts. There is no wasted goodness, no lost discipline. The universe does not punish sincerity -- even failed attempts accrue in your favor.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (49, 7, 7, 'mattaḥ parataraṁ nānyat kiñcid asti dhanañjaya', 'There is nothing whatsoever higher than Me, O Arjuna! All this is strung on Me as clusters of gems on a string.', 'Everything is connected by a single thread you can''t see. Your work, your relationships, that random conversation that changed your trajectory. They look separate from the inside. They''re not. The Gita uses the image of gems on a string. Each moment is a jewel. The string running through all of them is what gives your life coherence, even when it feels fragmented.', 'Look at three seemingly unrelated events from the past year. Find the thread. There usually is one.', 'What pattern keeps showing up in your life that you''ve been treating as coincidence?', 'This world is mere change, and this life, opinion.', 'Marcus Aurelius, Meditations, 4.3', 'Both Krishna and Marcus see behind the surface chaos to a single underlying principle. Krishna names it as the thread connecting all jewels. Marcus reduces it to two words.', '{"perspective","clarity"}', '{"underlying unity","coherence","interconnection"}', 'When life feels fragmented and meaningless. When you need to see the connecting thread that runs through your diverse experiences.', 'C', 'Everything is connected by a single underlying reality -- all things are strung on it like jewels on a thread. This is the Gita''s argument for coherence over chaos, for seeing the thread that runs through seemingly disparate experiences.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (50, 7, 11, 'balaṁ balavatāṁ cāhaṁ kāma-rāga-vivarjitam', 'Of the strong, I am the strength devoid of desire and attachment, and in (all) beings, I am the desire unopposed to Dharma, O Arjuna!', 'Strength isn''t the problem. Desire isn''t the problem. They become problems when they''re disconnected from purpose. The strongest person in the room who''s driven by ego is dangerous. The same person driven by genuine purpose is exactly who you want leading. Ambition doesn''t need to be killed. It needs to be aimed.', 'Think of your biggest ambition right now. Ask: is this driven by purpose or by ego? Be honest. Both answers are fine, but know which one is running things.', 'Where in your life is your strength disconnected from your purpose?', 'We must sacrifice many things to which we are addicted, thinking them to be goods. Gone is courage, which should be continually testing itself; gone is greatness of soul, which cannot stand out clearly unless it has learned to scorn as trivial everything that the crowd covets.', 'Seneca, Moral Letters, 74.12b-13', 'Both the Gita and Seneca teach that strength and desire must be filtered through ethical purpose. Raw power without direction isn''t virtue, but its precondition.', '{"courage","discipline"}', '{"ethical strength","desire aligned with dharma","ambition and virtue"}', 'When you wonder whether ambition itself is the problem -- the answer that ambition aligned with purpose is not greed, it is dharma.', 'C', 'Strength and desire are not inherently bad -- they become destructive only when divorced from ethical purpose. A verse that refuses the false choice between ambition and virtue.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (51, 7, 14, 'daivī hy eṣā guṇa-mayī mama māyā duratyayā', 'Verily this divine illusion of Mine made up of the qualities (of Nature) is difficult to cross over; those who take refuge in Me alone cross over this illusion.', 'The patterns that keep you asleep aren''t obvious. They''re woven into everything: your habits, your assumptions, the things you''ve never questioned because they feel like ''just the way things are.'' Seeing through them is hard. The Gita doesn''t pretend otherwise. But it''s possible. It just takes sustained attention, not a one-time revelation.', 'Pick one belief you hold about yourself (''I''m not creative,'' ''I''m bad with money'') and ask: where did I actually get this? Is it still true?', 'What assumption about your life have you never questioned because it''s been there so long it feels like a fact?', 'It is things that lead us astray: it is between things that you must discriminate. We embrace evil instead of good; we pray for something opposite to that which we have prayed for in the past.', 'Seneca, Moral Letters, 45.6', 'Both the Gita and Seneca acknowledge that the forces keeping us asleep are woven into experience itself. Overcoming them takes sustained discernment, not willpower alone.', '{"perspective","acceptance"}', '{"difficulty of awakening","conditioning as matrix","honest about the challenge"}', 'When you glimpse how deep your conditioning runs -- habits of thought, emotional patterns, inherited beliefs -- and feel daunted by the work ahead.', 'B', 'An honest admission that the matrix of conditioning is extremely hard to see through -- but it can be done. This verse neither sugarcoats the difficulty nor gives up hope.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (52, 8, 6, 'yaṁ yaṁ vāpi smaran bhāvaṁ tyajaty ante kalevaram', 'Whosoever at the end leaves the body, thinking of any being, to that being only does he go, O son of Kunti (Arjuna), because of his constant thought of that being!', 'You become what you think about. Not what you think about once, but what you return to again and again. Your mind is being dyed by whatever you keep exposing it to. Your news feed, your conversations, your late-night worries. These aren''t neutral. They''re forming you.', 'Do a quick audit of the last three things you consumed on your phone. Did they move you toward the person you want to be, or away?', 'If your habitual thoughts were shaping your future right now, where would you be heading?', 'Such as thy thoughts and ordinary cogitations are, such will thy mind be in time. For the soul doth as it were receive its tincture from the fancies, and imaginations.', 'Marcus Aurelius, Meditations, 5.16', 'Both the Gita and Marcus say the same thing: your mind takes the shape of what it frequently holds. Choose carefully, because this isn''t theoretical.', '{"clarity","discipline"}', '{"habitual thought shapes destiny","mental habits","neuroplasticity"}', 'When evaluating your media diet, your social circle, your daily mental habits -- the verse that says these are not neutral; they are forming you.', 'B', 'You become what you consistently think about. The quality of your habitual thoughts shapes your destination -- a verse that bridges memento mori with neuroplasticity.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (53, 8, 7, 'tasmāt sarveṣu kāleṣu mām anusmara yudhya ca', 'Therefore, at all times remember Me only and fight. With mind and intellect fixed (or absorbed) in Me, thou shalt doubtless come to Me alone.', 'Don''t compartmentalize. Your highest awareness doesn''t belong in a meditation session and nowhere else. Bring it to the meeting, the argument, the grocery store. The instruction is total: at all times. Not when it''s convenient. Not when you feel spiritual. Always. That''s the difference between someone who practices and someone who lives it.', 'Pick one mundane task today (washing dishes, commuting, eating) and do it with the same quality of attention you''d bring to something you consider important.', 'How different would your day be if you brought your best self to every single activity, not just the ''important'' ones?', 'Let us so order our minds as if we had come to the very end. Let us postpone nothing. Let us balance life''s account every day. One who daily puts the finishing touches to his life is never in want of time.', 'Seneca, Moral Letters, 101.7b-8a', 'Both Krishna and Seneca demand total integration: don''t save your deepest awareness for special occasions. Balance life''s books every day.', '{"discipline","courage"}', '{"non-compartmentalization","continuous awareness","integration of practice and life"}', 'When you meditate in the morning but lose all awareness by noon. When spiritual practice is a compartment rather than a coloring of everything you do.', 'C', 'Do not compartmentalize. Bring your highest awareness into every action, including the difficult and the mundane. This verse dissolves the false boundary between ''spiritual practice'' and ''regular life'' -- all of it is the arena.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (54, 9, 22, 'ananyāś cintayanto māṁ ye janāḥ paryupāsate', 'To those men who worship Me alone, thinking of no other, of those ever united, I secure what is not already possessed and preserve what they already possess.', 'Total commitment unlocks a kind of support you didn''t know existed. Call it grace, luck, compound interest, whatever. When you stop hedging your bets and go all in on what matters, things start breaking your way in ways you can''t plan for. Not because the universe is magical. Because focus works. Scattered attention produces scattered results.', 'Identify the one thing that deserves your full attention right now. Give it thirty minutes of completely undivided focus.', 'What would change if you stopped splitting your commitment across ten things and went all in on one?', 'But I have never been hindered in my will, nor compelled when I did not will. And how is this possible? I have placed my movements toward action in obedience to God.', 'Epictetus, Discourses, 4.1.89', 'Both teachings describe what happens when personal will fully aligns with purpose: resistance dissolves and support appears.', '{"patience","courage"}', '{"total commitment","provision","faith in the path"}', 'When you have been working toward something for a long time and wonder if it will ever pay off. When commitment feels unrewarded.', 'C', 'Total commitment to a path activates support you did not know existed -- whether you frame that as grace, luck, or compound interest. This verse rewards dedication with a promise of provision.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (55, 9, 27, 'yat karoṣi yad aśnāsi yaj juhoṣi dadāsi yat', 'Whatever thou doest, whatever thou eatest, whatever thou offerest in sacrifice, whatever thou givest, whatever thou practiseth as austerity, O Arjuna, do it as an offering unto Me!', 'Whatever you do, do it as an offering. Not to impress anyone. Not for the result. As a gift to something bigger than your to-do list. This reframes everything. Making dinner isn''t a chore. It''s an offering. Going to work isn''t a grind. It''s an offering. Even the boring parts. Especially the boring parts. Because meaning doesn''t live in the task. It lives in how you hold it.', 'Pick the most boring task on your list today. Before you start it, silently say: ''This one''s an offering.'' See if it changes the quality of your attention.', 'What would shift if you treated everything you did today, even the trivial stuff, as something you were giving rather than enduring?', 'Whatsoever thou dost affect, whatsoever thou dost project, so do, and so project all, as one who, for aught thou knowest, may at this very present depart out of this life.', 'Marcus Aurelius, Meditations, 2.11', 'Both the Gita and Marcus elevate ordinary actions by connecting them to something larger. The Gita uses offering. Marcus uses mortality. Both turn every mundane act into something deliberate.', '{"discipline","perspective"}', '{"sacred mundane","dedication","intention in ordinary acts"}', 'When daily routines feel meaningless -- cooking, commuting, working -- the reframe that every mundane act can carry the weight of devotion.', 'C', 'Transform the mundane into the sacred by dedicating it to something larger than yourself. Eating, working, giving -- all become meaningful when offered with intention.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (56, 9, 34, 'man-manā bhava mad-bhakto mad-yājī māṁ namaskuru', 'Fix thy mind on Me; be devoted to Me; sacrifice unto Me; bow down to Me; having thus united thy whole self with Me, taking Me as the Supreme Goal, thou shalt verily come unto Me.', 'Pick your highest ideal and give it everything. Not some of your attention. All of it. Whether you call it God, truth, purpose, or just ''the thing that matters most,'' commit completely. Half-measures produce half-results. The person who meditates for five minutes while checking email isn''t meditating. Total dedication to one thing beats scattered effort across twenty.', 'Write down the one thing that matters most to you right now. Put it where you''ll see it first thing tomorrow morning.', 'What would you commit to completely if you weren''t afraid it might not work out?', 'What, then, is that which makes a man free from hindrance and makes him his own master? For wealth does not do it, nor consulship, nor provincial government, nor royal power; but something else must be discovered. Therefore in life also it is the science of life.', 'Epictetus, Discourses, 4.1.62-64', 'Both Krishna and Epictetus describe the same turning point: the moment you stop being scattered and commit fully to what matters most. That''s where mastery and freedom begin.', '{"discipline","acceptance"}', '{"total dedication","single-pointed commitment","devotion as practice"}', 'When your attention is scattered across a dozen competing commitments. When you need to pick the one thing that deserves your full devotion and give it everything.', 'C', 'Total dedication to your highest ideal -- whether you call it God, purpose, or truth -- is the path. This verse is not about religious devotion but about the transformative power of single-pointed commitment to what matters most.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (57, 10, 4, 'buddhir jñānam asammohaḥ kṣamā satyaṁ damaḥ śamaḥ', 'Intellect, wisdom, non-delusion, forgiveness, truth, self-restraint, calmness, happiness, pain, birth or existence, death or non-existence, fear and also fearlessness,', 'Every quality you experience, good and bad, is part of the same fabric. Intelligence, confusion, courage, fear, joy, pain. None of it is alien to existence. Your worst day and your best day are both made of the same material. That doesn''t make the bad days good. But it does mean you''re not broken when you''re afraid, confused, or hurting. You''re just experiencing the full range of what it means to be alive.', 'Name one quality you''re ashamed of (fear, anger, confusion). Now try this: instead of fighting it, acknowledge it as part of being human. Just for today.', 'What part of your experience are you trying to amputate instead of accepting?', 'Think of the life you have lived until now as over and, as a dead man, see what''s left as a bonus and live it according to Nature.', 'Marcus Aurelius, Meditations, 7.56', 'Both the Gita and Marcus teach radical acceptance of the full hand you''ve been dealt. Not just the pleasant cards, but the difficult ones too.', '{"perspective","acceptance"}', '{"all qualities are natural","normalizing experience","the full spectrum"}', 'When you feel that your particular struggles are uniquely broken or alien -- the perspective that every quality, positive or negative, belongs to the same fabric.', 'C', 'Every human quality -- intelligence, patience, fear, fearlessness, suffering, happiness -- is part of the fabric of reality. Nothing you experience is alien to existence. This normalizes the full range of human experience.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (58, 10, 10, 'teṣāṁ satata-yuktānāṁ bhajatāṁ prīti-pūrvakam', 'To them who are ever steadfast, worshipping Me with love, I give the Yoga of discrimination by which they come to Me.', 'Consistency unlocks understanding. Not brilliance, not talent, not luck. Just showing up again and again with genuine effort. The insight you''re waiting for isn''t going to arrive in a flash. It''s going to arrive after you''ve practiced long enough that your mind reorganizes itself around the practice. Like fruit ripening. You can''t speed it up. You can only keep watering the tree.', 'Whatever practice feels like it''s ''not working,'' commit to thirty more days before you evaluate. Not thirty days of intensity. Just thirty days of showing up.', 'What are you quitting too early because you expected results faster than reality delivers?', 'Nothing great is produced suddenly, since not even the grape or the fig is. If you say to me now that you want a fig, I will answer to you that it requires time: let it flower first, then put forth fruit, and then ripen.', 'Epictetus, Discourses, 1.15.7-8', 'Both Krishna and Epictetus use the same patient architecture: understanding ripens like fruit. It can''t be rushed. Consistent practice is the sunlight.', '{"patience","discipline"}', '{"consistency","earned insight","practice over time"}', 'When you have been practicing for months and see no results. When you need the reassurance that consistent effort is silently accumulating toward a breakthrough you cannot yet see.', 'C', 'Consistent practice unlocks understanding. Insight is not a lightning bolt -- it is earned through dedication. The verse promises that for those who engage constantly, understanding will come, but only through sustained effort over time.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (59, 10, 41, 'yad yad vibhūtimat sattvaṁ śrīmad ūrjitam eva vā', 'Whatever being there is that is glorious, prosperous or powerful, that know thou to be a manifestation of a part of My splendour.', 'Every time you see something excellent, that''s a glimpse of something bigger. A perfect sunset, an athlete in flow, a piece of music that stops you cold. Those aren''t random. They''re fragments of a coherence that runs through everything. Training yourself to notice these moments turns ordinary life into something consistently astonishing. Not because life changed. Because your attention did.', 'Notice three beautiful or excellent things today that you''d normally walk past. A well-made building, a kind interaction, a good cup of coffee. Actually pause for each one.', 'When was the last time you stopped to appreciate something excellent without immediately moving on to the next thing?', 'Who can choose but wonder at them? They will not speak well of them that are at the same time with them, and live with them; yet they themselves are very ambitious, that they that shall follow, whom they have never seen, nor shall ever see, should speak well of them.', 'Marcus Aurelius, Meditations, 6.18', 'Both the Gita and Marcus invite a way of seeing that finds coherence in the whole. The Gita sees divine splendour in excellence. Marcus sees irony in our blindness to it.', '{"perspective","clarity"}', '{"reverence","seeing the divine in excellence","wonder as practice"}', 'When the world feels fragmented and chaotic -- the practice of noticing excellence, beauty, and strength as evidence of an underlying coherence.', 'C', 'Every instance of beauty, excellence, and power you encounter in the world is a fragment of something larger. This verse cultivates reverence as a daily practice rather than a Sunday ritual.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (60, 11, 32, 'kālo ''smi loka-kṣaya-kṛt pravṛddho lokān samāhartum iha pravṛttaḥ', 'I am the mighty world-destroying Time, now engaged in destroying the worlds. Even without thee, none of the warriors arrayed in the hostile armies shall live.', 'This is the cosmic cold shower. ''I am Time, the destroyer of worlds.'' Oppenheimer quoted it, and it still hits. Everything you''re worried about today, your reputation, your performance review, that argument, none of it survives the long game. That''s not depressing. It''s freeing. If none of it lasts, you might as well stop clutching it so tightly.', 'Think of the thing consuming most of your mental energy today. Now fast-forward 100 years. Notice how the grip loosens.', 'What would you stop caring about if you truly believed none of this was permanent?', 'Alexander of Macedon, and he that dressed his mules, when once dead both came to one.', 'Marcus Aurelius, Meditations, 6.24', 'Both the Gita and Marcus use death to dissolve the illusion that status or achievement can be made permanent. Alexander and his mule-keeper end up in the same place.', '{"perspective","acceptance"}', '{"time as destroyer","radical impermanence","liberation through perspective"}', 'When you are taking yourself, your problems, or your achievements too seriously -- the cosmic cold shower that resets perspective.', 'A', 'The ultimate perspective check: ''I am time, the great destroyer.'' This is not nihilism -- it is liberation from the illusion of permanence. Oppenheimer quoted it for good reason; it remains the Gita''s most viscerally powerful moment.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (61, 11, 33, 'tasmāt tvam uttiṣṭha yaśo labhasva jitvā śatrūn bhuṅkṣva rājyaṁ samṛddham', 'Therefore, stand up and obtain fame. Conquer the enemies and enjoy the unrivalled kingdom. Verily, they have already been slain by Me; be thou a mere instrument, O Arjuna!', 'Stop agonizing. The outcome is already in motion. You''re not the author of what happens next. You''re the instrument. Your only job is to stand up and act. This is the most galvanizing verse in the Gita: it doesn''t ask you to figure everything out. It just asks you to show up.', 'Identify one thing you''ve been overthinking. Stand up (literally, if you can) and take the first physical action toward it.', 'What are you waiting for permission to do that you already know you need to start?', 'It is circumstances which show what men are. Therefore when a difficulty falls upon you, remember that God, like a trainer of wrestlers, has matched you with a rough young man. For what purpose? Why, that you may become an Olympic conqueror; but it is not accomplished without sweat.', 'Epictetus, Discourses, 1.24.1-2', 'Both the Gita and Epictetus reframe difficulty the same way: you''re not being punished by what''s being asked of you. You''re being trained. Your job is to rise to it.', '{"courage","acceptance"}', '{"arise and act","instrument not author","surrender to the larger process"}', 'The verse to read before the battle, the launch, the confrontation, the surgery, the speech -- any moment where you must act despite uncertainty about the outcome.', 'A', 'Stop agonizing over outcomes that are already unfolding. Your job is to show up and act -- you are the instrument, not the author. The single most galvanizing verse in the Gita.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (62, 11, 55, 'mat-karma-kṛn mat-paramo mad-bhaktaḥ saṅga-varjitaḥ', 'He who does all actions for Me, who looks upon Me as the Supreme, who is devoted to Me, who is free from attachment, who bears enmity towards no creature, he comes to Me, O Arjuna!', 'Here''s the entire blueprint in one verse. Do your work with purpose. Stay devoted to what matters. Let go of attachment. Don''t carry grudges. That''s it. Four instructions. Not twenty books, not a decade-long program. If you could genuinely do these four things for even one day, you''d recognize the person you''d become.', 'Pick just one of the four today: purposeful action, devotion, letting go, or goodwill toward all. Practice that one thing until bedtime.', 'Which of these four (purpose, devotion, non-attachment, goodwill) would transform your life most if you actually practiced it?', 'Make it not any longer a matter of dispute or discourse, what are the signs and proprieties of a good man, but really and actually to be such.', 'Marcus Aurelius, Meditations, 10.16', 'The Gita gives the detailed blueprint. Marcus gives the summary: stop debating what a good person looks like and be one.', '{"discipline","acceptance"}', '{"complete life blueprint","purposeful action","goodwill toward all"}', 'When you need a concise standard to measure your life against. When the complexity of ethics overwhelms and you need a single-verse blueprint for how to live.', 'C', 'The complete person: purposeful action, devotion to something higher, non-attachment, and goodwill toward all beings. A concise life blueprint that covers doing, believing, releasing, and relating -- all in a single verse.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (63, 12, 8, 'mayy eva mana ādhatsva mayi buddhiṁ niveśaya', 'Fix thy mind on Me only, thy intellect in Me, (then) thou shalt no doubt live in Me alone hereafter.', 'Where you put your attention is where you actually live. Not where your body is. Where your mind is. If your mind is on your phone during dinner, you''re not at dinner. If your mind is on worry during a sunset, you missed the sunset. This verse is the ancient version of ''be here now,'' except it''s more specific: fix your mind on what matters most. Everything else follows.', 'For the next ten minutes, put your phone in another room. Notice where your mind goes when it can''t reach for the screen.', 'Where does your mind actually spend most of its time, and is that where you want to live?', 'Look within; within is the fountain of all good. Such a fountain, where springing waters can never fail, so thou dig still deeper and deeper.', 'Marcus Aurelius, Meditations, 7.59', 'Both Krishna and Marcus direct attention inward with the same promise: what you seek is already within you, but only sustained focus will uncover it.', '{"clarity","discipline"}', '{"attention as destiny","focus","psychological residence"}', 'When your attention is captured by every notification, distraction, and passing stimulus. When you need to remember that where your mind dwells is where you actually live.', 'C', 'Where you place your attention determines where you live psychologically. This verse reduces all spiritual instruction to a single directive: fix your mind on what matters most, and let your intellect dwell there. Attention is everything.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (64, 12, 12, 'śreyo hi jñānam abhyāsāj jñānād dhyānaṁ viśiṣyate', 'Better indeed is knowledge than practice; than knowledge meditation is better; than meditation the renunciation of the fruits of actions; peace immediately follows renunciation.', 'If you can only do one thing, do this: let go of results. The Gita ranks all the spiritual practices and puts this one at the top. Not meditation, not study, not discipline. Just releasing your grip on how things turn out. Peace follows immediately. Not eventually. Immediately.', 'Pick one thing you''re anxiously awaiting the outcome of. Imagine the worst version. Now the best. Notice: you''re okay in both. Let go.', 'What result are you holding onto so tightly that the holding itself has become the source of your suffering?', 'Don''t seek for everything to happen as you wish it would, but rather wish that everything happens as it actually will, then your life will flow well.', 'Epictetus, Enchiridion, 8', 'Both the Gita and Epictetus arrive at the same destination: stop insisting things should be different from what they are, and peace follows immediately.', '{"acceptance","clarity"}', '{"hierarchy of practices","renunciation of fruits","peace through letting go"}', 'When overwhelmed by too many spiritual or self-improvement practices -- the verse that simplifies everything to a single instruction: release your grip on results.', 'A', 'A hierarchy of practices ending with the ultimate: let go of results. If you can do only one thing, do that. The verse that ranks all spiritual practices and puts non-attachment at the top.', true, false, 'Enchiridion text not available in public domain source files; quote sourced from modern translation.');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (65, 12, 13, 'adveṣṭā sarva-bhūtānāṁ maitraḥ karuṇa eva ca', 'He who hates no creature, who is friendly and compassionate to all, who is free from attachment and egoism, balanced in pleasure and pain, and forgiving,', 'This is a character checklist, and it''s worth going through honestly. Do you hate anyone? Are you genuinely friendly, not just polite? Free from ego, or just good at hiding it? Can you handle pleasure and pain without either one running you? Are you forgiving? Not as a theory. Actually forgiving. Right now.', 'Pick one quality from this list that you''re weakest on today. Don''t try to fix it. Just notice it. Awareness comes first.', 'If you were graded on friendliness, humility, and forgiveness today, what would the report card look like?', 'Make it not any longer a matter of dispute or discourse, what are the signs and proprieties of a good man, but really and actually to be such.', 'Marcus Aurelius, Meditations, 10.16', 'The Gita gives the detailed checklist. Marcus gives the summary: stop debating what a good person looks like and be one.', '{"patience","discipline"}', '{"the ideal character","self-assessment checklist","comprehensive virtue"}', 'As an annual or quarterly self-review: read the list of qualities, honestly assess where you stand on each, and identify the one or two to focus on next.', 'A', 'The most detailed character portrait of the ideal person in the Gita -- friendly, compassionate, free from ego, equal in pain and pleasure, forgiving, content, self-controlled. A practical checklist for self-assessment.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (66, 12, 15, 'yasmān nodvijate loko lokān nodvijate ca yaḥ', 'He by whom the world is not agitated and who cannot be agitated by the world, and who is freed from joy, envy, fear and anxiety, he is dear to Me.', 'Here''s a simple test: do people tense up when you enter the room, or relax? And when the room gets tense, do you absorb it or stay steady? The ideal is someone who neither creates agitation nor catches it. That''s a rare person and a remarkably useful one.', 'In your next interaction today, notice whether you''re adding calm or adding static. Don''t judge it. Just observe.', 'Does the world agitate you more, or do you agitate the world more?', 'Will any contemn me? let him look to that, upon what grounds he does it: my care shall be that I may never be found either doing or speaking anything that doth truly deserve contempt.', 'Marcus Aurelius, Meditations, 11.13', 'Both the Gita and Marcus say the same thing: manage your own behavior and let the world''s opinion of you be the world''s problem.', '{"patience","acceptance"}', '{"reciprocal non-reactivity","peace as mirror","world reflects self"}', 'When the world feels adversarial and hostile -- the check to ask whether the hostility originates in the world or in your own reactivity to it.', 'B', 'The reciprocal principle: if you stop being reactive, the world stops feeling hostile. Your relationship to the world mirrors the world''s relationship to you.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (67, 12, 16, 'anapekṣaḥ śucir dakṣa udāsīno gata-vyathaḥ', 'He who is free from wants, pure, expert, unconcerned, and untroubled, renouncing all undertakings or commencements, he who is (thus) devoted to Me, is dear to Me.', 'Free from wants, capable, unconcerned, untroubled. That''s not describing someone who''s checked out. That''s describing someone operating at peak capacity without the dead weight of neediness. They''re excellent at what they do, but they don''t need your approval to do it. That combination of competence and independence is rare. It''s also the kind of person everyone wants on their team.', 'Do one thing today purely for the quality of it, with zero expectation of feedback. Don''t mention it to anyone. See how that feels.', 'How much of your effort is driven by the work itself, and how much by the need to be seen doing it?', 'The ambitious supposeth another man''s act, praise and applause, to be his own happiness; the voluptuous his own sense and feeling; but he that is wise, his own action.', 'Marcus Aurelius, Meditations, 6.51', 'Both the Gita and Marcus describe the highest operating mode: full capability deployed without dependence on recognition, reward, or praise.', '{"discipline","clarity"}', '{"competence without neediness","effective peace","desireless capability"}', 'For anyone in a leadership or service role who needs to perform at a high level without becoming enslaved to the approval of those they serve.', 'B', 'Competence without neediness -- the profile of someone who is both effective and at peace. Free from expectations, pure, capable, impartial, undisturbed. A leadership standard that transcends culture.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (68, 12, 18, 'samaḥ śatrau ca mitre ca tathā mānāpamānayoḥ', 'He who is the same to foe and friend, and in honour and dishonour, who is the same in cold and heat and in pleasure and pain, who is free from attachment,', 'Same toward your enemy and your friend. Same when people praise you and when they tear you apart. Same in comfort and pain. This sounds superhuman, and honestly, it kind of is. But it''s the goal. Not because feelings don''t matter, but because consistency does. The person who''s steady in all conditions is the one you trust with everything.', 'Think of someone who annoys you. Now think of someone you love. Try, just for a moment, to wish them both well equally. Notice how hard it is.', 'Where does your behavior change most dramatically depending on who''s watching?', 'He must adapt his wish to what is going on, so that nothing takes place contrary to his wish, and nothing that he wishes for fails to take place.', 'Epictetus, Discourses, 2.14.7', 'Both the Gita and Epictetus describe the same aspiration: a person so aligned with reality that no circumstance can dislodge their composure.', '{"acceptance","patience"}', '{"equanimity in all conditions","equal toward opposites","universal steadiness"}', 'When life hands you the full spectrum in rapid succession -- praise followed by criticism, success followed by failure -- and you need a single standard for how to meet it all.', 'A', 'Equal toward enemy and friend, in honor and dishonor, in cold and heat, happiness and suffering. Stoic equanimity rendered in complete detail -- a verse Marcus Aurelius could have written.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (69, 13, 8, 'amānitvam adambhitvam ahiṁsā kṣāntir ārjavam', 'Humility, unpretentiousness, non-injury, forgiveness, uprightness, service of the teacher, purity, steadfastness, self-control,', 'This is a shopping list for character, and it starts with humility. Not the fake kind where you pretend you''re not good at things. The real kind where you know what you can do and don''t need to perform it for an audience. Unpretentious. Non-violent. Forgiving. Honest. Steady. Self-controlled. It''s not a personality. It''s a practice.', 'Pick one quality from the list you''re weakest on this week: humility, honesty, patience, or self-control. Focus on just that one.', 'If someone who knew you well had to rank these qualities in you, which would be at the bottom?', 'Keep thyself therefore, truly simple, good, sincere, grave, free from all ostentation, a lover of that which is just, religious, kind, tender-hearted, strong and vigorous to undergo anything that becomes thee.', 'Marcus Aurelius, Meditations, 6.30', 'Both the Gita and Marcus produce nearly identical virtue lists. And both insist that these qualities ARE the knowledge, not accessories to it.', '{"discipline","patience"}', '{"character as knowledge","virtue list","humility"}', 'When you have read every book but your life has not changed. When knowledge has become a substitute for transformation.', 'B', 'A comprehensive list of qualities that constitute real knowledge: humility, non-violence, patience, honesty, self-control. Not information but character. The Gita defines knowledge by what it produces in you, not what you can recite.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (70, 13, 28, 'samaṁ sarveṣu bhūteṣu tiṣṭhantaṁ parameśvaram', 'He sees, who sees the Supreme Lord, existing equally in all beings, the unperishing within the perishing.', 'Real seeing isn''t about what someone looks like or what title they carry. It''s about recognizing the same essential dignity in every person you meet. The barista, the CEO, the person who cut you off in traffic. Same underlying reality. Different packaging. Getting this isn''t a moral achievement. It''s a perceptual one. You train your eyes to see what''s actually there.', 'In your next three conversations today, silently remind yourself: this person is dealing with the same fundamental human situation I am.', 'Who do you consistently see as ''other,'' and what would change if you recognized your shared humanity?', 'If thou shouldst live three thousand, or as many as ten thousands of years, yet remember this, that man can part with no life properly, save with that little part of life, which he now lives: and that which he lives, is no other, than that which at every instant he parts with.', 'Marcus Aurelius, Meditations, 2.14', 'Both Krishna and Marcus reveal that beneath all surface distinctions, every being shares the same fundamental present moment. The differences we obsess over dissolve when seen clearly.', '{"perspective","acceptance"}', '{"equal vision","dignity","seeing beyond surfaces"}', 'When you catch yourself judging people by status, appearance, or background. When you need to remember the shared humanity beneath every surface difference.', 'C', 'Seeing the same essential dignity in every person regardless of surface differences. This is the Gita''s most direct teaching on equality -- not as ideology but as perception.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (71, 13, 34, 'kṣetra-kṣetrajñayor evam antaraṁ jñāna-cakṣuṣā', 'Just as the one sun illumines the whole world, so also the Lord of the Field (the Supreme Self) illumines the whole Field, O Arjuna!', 'You are not your thoughts. You are not your body. You are not your circumstances. You''re the awareness watching all of it. That sounds abstract until you''ve had even one moment of watching your own mind panic while some deeper part of you stays perfectly calm. That deeper part is what this verse is pointing at.', 'Close your eyes for 30 seconds. Watch your thoughts like you''d watch cars passing on a highway. You''re not the cars. You''re the one watching.', 'What would change if you stopped identifying with your thoughts and started watching them instead?', 'This day I did come out of all my trouble. Nay I have cast out all my trouble; for that which troubled thee, was not without anywhere that thou shouldest come out of it, but within in thine own opinions, from whence it must be cast out, before thou canst truly and constantly be at ease.', 'Marcus Aurelius, Meditations, 9.13', 'Both the Gita and Marcus locate freedom in the same realization: the trouble is never outside you. It''s in your opinions about what''s outside you.', '{"clarity","perspective"}', '{"awareness vs. content","observer and observed","liberation through discernment"}', 'When you are over-identified with a role, a body, or a set of thoughts. When you need to step back and remember what you actually are.', 'A', 'The fundamental insight of the Gita''s metaphysics: you are not your thoughts, body, or circumstances -- you are the awareness observing them. This single distinction, when grasped experientially, changes everything.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (72, 14, 5, 'sattvaṁ rajas tama iti guṇāḥ prakṛti-sambhavāḥ', 'Purity, passion and inertia, these qualities, O mighty-armed Arjuna, born of Nature, bind fast in the body, the embodied, the indestructible!', 'Your moods follow three patterns. Clarity (you can think straight, everything feels workable). Agitation (you''re restless, scattered, can''t sit still). Inertia (you can''t get off the couch, everything feels heavy). Recognizing which one is running you at any given moment is half the battle. You''re not broken on a bad day. You''re just in a different mode. And modes shift.', 'Right now, check in: am I in clarity, agitation, or inertia? Don''t judge it. Just name it. That''s the diagnostic.', 'Which of the three modes (clarity, agitation, inertia) do you spend the most time in, and what triggers each one?', 'Make it not any longer a matter of dispute or discourse, what are the signs and proprieties of a good man, but really and actually to be such.', 'Marcus Aurelius, Meditations, 10.16', 'Both the Gita''s framework and Marcus''s instruction to ''know things for what they are'' provide diagnostic tools for inner states. Name the pattern, and you gain power over it.', '{"clarity","perspective"}', '{"three gunas","mood diagnosis","self-understanding"}', 'When your mood shifts and you do not understand why. When you need a simple framework to diagnose whether you are in clarity, agitation, or inertia.', 'B', 'Your moods, drives, and mental states follow recognizable patterns -- clarity, agitation, inertia. Naming them as sattva, rajas, and tamas gives you a diagnostic framework for understanding why you feel the way you do on any given day.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (73, 14, 8, 'tamas tv ajñāna-jaṁ viddhi mohanaṁ sarva-dehinām', 'But know thou Tamas to be born of ignorance, deluding all embodied beings; it binds fast, O Arjuna, by heedlessness, sleep and indolence!', 'Inertia is born from not seeing clearly. And it binds you with three things: not paying attention, sleeping too much, and plain laziness. If you''ve ever spent an entire day on the couch feeling like you couldn''t move, you know exactly what this feels like. The Gita doesn''t shame you for it. It just names the mechanism. Naming it is the first step to breaking free of it.', 'If you''re stuck in inertia right now, do one small thing. Wash one dish. Send one email. Take one walk around the block. Movement breaks the spell.', 'What are you calling ''rest'' right now that is actually avoidance in disguise?', 'In the morning when thou findest thyself unwilling to rise, consider with thyself presently, it is to go about a man''s work that I am stirred up. Am I then yet unwilling to go about that, for which I myself was born and brought forth into this world? Or was I made for this, to lay me down, and make much of myself in a warm bed?', 'Marcus Aurelius, Meditations, 5.1', 'Both Krishna and Marcus diagnose the same enemy: the gravitational pull of comfort, sleep, and inaction. Both prescribe the same antidote: remember what you''re actually here to do.', '{"clarity","discipline"}', '{"tamas","inertia","procrastination","depression"}', 'When stuck in a fog of inaction. When procrastination has become a chronic pattern and you need to see the mechanism clearly before you can break it.', 'C', 'A precise description of the tamasic state: ignorance, negligence, indolence, sleep. This maps directly onto depression, procrastination, and the inertia that keeps people stuck. Naming the mechanism is the first step to escaping it.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (74, 14, 22, 'prakāśaṁ ca pravṛttiṁ ca moham eva ca pāṇḍava', 'Light, activity and delusion, when they are present, O Arjuna, he hates not, nor does he long for them when they are absent!', 'Advanced move: stop fighting your mental states. When clarity shows up, don''t cling to it. When agitation arrives, don''t panic. When inertia settles in, don''t hate yourself. Just watch. All three are weather systems passing through you. They don''t need your commentary. This isn''t indifference. It''s the kind of observation that lets everything pass without sticking.', 'The next time your mood shifts (good or bad), try saying: ''This is here right now. It won''t be here forever.'' Then get back to what you were doing.', 'How much energy do you spend trying to control your moods instead of simply observing them?', 'It is not things that disturb us, but our judgments about things.', 'Epictetus, Enchiridion, 5', 'Both the Gita and Epictetus identify the same advanced insight: it''s not your mental states that bind you, but your judgments about them. Observe without judging, and they pass through like weather.', '{"acceptance","perspective"}', '{"non-identification","weather-watching the mind","transcending the gunas"}', 'When you have tried to control your moods and failed. When you are ready for the more advanced approach: stop trying to manage states and start observing them.', 'B', 'Advanced emotional regulation: observe your mental states as weather systems passing through without identifying with them. Do not chase clarity or flee inertia -- just watch. This is the Gita''s most sophisticated instruction on non-reactive awareness.', true, false, 'Enchiridion text not available in public domain source files; quote sourced from standard translation.');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (75, 15, 3, 'na rūpam asyeha tathopalabhyate nānto na cādir na ca sampratiṣṭhā', 'Its form is not perceived here as such, neither its end nor its origin, nor its foundation nor resting place; having cut asunder this firmly-rooted peepul tree with the strong axe of non-attachment,', 'Some things can''t be reasoned away. They have to be cut. The Gita uses the image of an axe of non-attachment cutting through a deeply rooted tree. Not a gentle untangling. A clean cut. If there''s a pattern, a relationship, a habit that has you tangled up, sometimes the wisest move isn''t to understand it better. It''s to put it down.', 'Name one thing you''re holding onto that you know you need to let go of. You don''t have to drop it today. Just name it.', 'What are you tangled in right now that would require a clean cut rather than a slow untangling?', 'In short, you must remember this, that if you hold anything dear outside of your own reasoned choice, you will have destroyed your capacity for choice. In short, remember this, that what you shall prize which is beyond your will, so far you have destroyed your will.', 'Epictetus, Discourses, 4.4.23', 'Both the Gita''s axe of detachment and Epictetus''s warning about clinging describe the same truth: anything you hold outside your own agency becomes a chain.', '{"courage","clarity"}', '{"detachment as tool","cutting through","purposeful renunciation"}', 'When you know something must be cut from your life but hesitate. When detachment feels like loss rather than liberation.', 'C', 'Detachment as a precision surgical tool rather than a blunt withdrawal. Cut the tree of entanglement at its root with the axe of dispassion, then move forward. This verse dignifies detachment as active and purposeful.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (76, 15, 5, 'nirmāna-mohā jita-saṅga-doṣāḥ adhyātma-nityā vinivṛtta-kāmāḥ', 'Free from pride and delusion, victorious over the evil of attachment, dwelling constantly in the Self, their desires having completely turned away, freed from the pairs of opposites known as pleasure and pain, the undeluded reach the eternal goal.', 'This is the destination, drawn in full detail. No pride. No delusion. No clinging. Desire has turned away, not been suppressed but genuinely released. Pleasure and pain no longer run the show. This isn''t a superhuman fantasy. It''s what happens when you practice long enough. You don''t arrive all at once. But you notice one day that things that used to grip you just... don''t.', 'Think of something you used to desperately want that you''ve moved past. Notice: the release didn''t kill you. It freed you. That''s what this feels like, just bigger.', 'What would genuine freedom from wanting look like in your life right now?', 'And it is never possible for happiness and desire of what is not present to come together. That which is happy must have all that it desires, must resemble a person who is filled with food, and must have neither thirst nor hunger.', 'Epictetus, Discourses, 3.24.17', 'Both Krishna and Epictetus define the liberated state the same way: complete ease arising from the absence of craving, not from getting everything you want.', '{"acceptance","discipline"}', '{"freedom from pride","ease of being","desirelessness"}', 'When you are exhausted by striving. When you wonder what it would feel like to genuinely have nothing to prove.', 'C', 'The portrait of the destination: free from pride, delusion, and attachment. Desires extinguished, dwelling in the self. Not ascetic withdrawal but genuine ease -- a person who has nothing left to prove, possess, or control.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (77, 15, 10, 'utkrāmantaṁ sthitaṁ vāpi bhuñjānaṁ vā guṇānvitam', 'The deluded do not see Him who departs, stays and enjoys; but they who possess the eye of knowledge behold Him.', 'Most people sleepwalk through their experience. They eat without tasting, work without presence, love without attention. Then they wonder why life feels flat. The ''eye of knowledge'' isn''t some mystical power. It''s just the habit of actually being where you are. Paying attention. Noticing what''s already happening instead of constantly looking ahead to what''s next.', 'During your next meal, put your phone away and actually taste the food. For the whole meal. That''s the eye of knowledge in miniature.', 'What are you missing in your daily life because you''ve stopped actually paying attention?', 'It is in thy power absolutely to exclude all manner of conceit and opinion, as concerning this matter; and by the same means, to exclude all grief and sorrow from thy soul.', 'Marcus Aurelius, Meditations, 6.52', 'Both Krishna and Marcus identify the same capacity: the ability to truly see, which requires choosing awareness over the default state of autopilot.', '{"clarity","perspective"}', '{"awareness as choice","sleepwalking","eye of knowledge"}', 'When you are going through the motions. When you suspect that you are missing something obvious because you have stopped paying attention.', 'C', 'Most people sleepwalk through their experience. The deluded do not see; those with the eye of knowledge see. Awareness is a choice that must be cultivated -- this verse makes that distinction vivid and urgent.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (78, 16, 1, 'abhayaṁ sattva-saṁśuddhir jñāna-yoga-vyavasthitiḥ', 'Fearlessness, purity of heart, steadfastness in Yoga and knowledge, alms-giving, control of the senses, sacrifice, study of scriptures, austerity and straightforwardness,', 'Fearlessness leads the list. Not courage, which implies you feel the fear and push through. Fearlessness. As in: you''ve done enough inner work that the fear itself has lost its grip. It''s listed before purity, before discipline, before knowledge. Because without it, none of the other qualities can fully show up.', 'Identify one thing you''re afraid of doing today. It doesn''t have to be huge. Send the message, ask the question, make the call.', 'What quality on this list (fearlessness, purity, steadfastness, generosity, self-control, honesty) are you most neglecting right now?', 'Do you then consider that the chief of all evils to man and the chief mark of mean spirit and of cowardice is not death, but rather the fear of death? Against this fear then I advise you to exercise yourself, and you will know that thus only are men made free.', 'Epictetus, Discourses, 3.26.38-39', 'Both the Gita and Epictetus put fearlessness at the foundation of all virtue. Without it, everything else is just decoration.', '{"courage","discipline"}', '{"divine qualities","character inventory","fearlessness"}', 'When assessing your character honestly. When you want a concrete list of qualities to develop, ordered by priority.', 'A', 'The complete inventory of divine qualities -- fearlessness first, then purity, steadfastness, charity, self-control, honesty, non-violence, truth, compassion. This is the Gita''s most comprehensive character development checklist, and fearlessness leads for a reason.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (79, 16, 21, 'tri-vidhaṁ narakasyedaṁ dvāraṁ nāśanam ātmanaḥ', 'Triple is the gate of this hell, destructive of the self, lust, anger, and greed, therefore, one should abandon these three.', 'Three gates lead to self-destruction: lust, anger, and greed. That''s it. Not a complicated taxonomy. Just three things. Before you make any important decision, run it through the filter: is lust, anger, or greed driving this? If the answer is yes to any of those, stop. Walk it off. Decide later.', 'Run your current biggest source of stress through the three-gate test: is desire, anger, or greed driving your reaction? Name it honestly.', 'Which of the three gates (desire, anger, greed) has the most influence over your decisions right now?', 'Meekness is a thing unconquerable, if it be true and natural, and not affected or hypocritical.', 'Marcus Aurelius, Meditations, 11.18', 'Both the Gita and Marcus identify anger as a gate to self-destruction and redefine strength: real power is the capacity for calm when rage is calling.', '{"clarity","discipline"}', '{"three gates of hell","self-destruction","diagnostic clarity"}', 'When you suspect that desire, anger, or greed is behind a decision you are about to make. When you need a simple test to run before acting.', 'A', 'Three gates of self-destruction: desire, anger, and greed. A ruthlessly clear diagnostic. If any of these three is driving your decisions, you are heading toward ruin. The simplicity is the power.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (80, 16, 24, 'tasmāc chāstraṁ pramāṇaṁ te kāryākārya-vyavasthitau', 'Therefore, let the scripture be the authority in determining what ought to be done and what ought not to be done. Having known what is said in the ordinance of the scriptures, thou shouldst act here in this world.', 'Have a framework. Don''t improvise your ethics under pressure. When things get hard and fast, you need principles you''ve already thought through, not real-time moral calculations. Whether your framework comes from philosophy, religion, or hard experience, the point is the same: decide what you stand for before the moment of crisis, not during it.', 'Write down three non-negotiable principles you live by. Keep them somewhere you''ll see them when things get hard.', 'What principles are you operating by right now, and did you choose them deliberately or absorb them by accident?', 'Some things are in our power, while others are not. We control our opinion, choice, desire, aversion, and, in a word, everything of our own doing. We don''t control our body, property, reputation, position, and, in a word, everything not of our own doing.', 'Epictetus, Enchiridion, 1.1-2', 'Both Krishna and Epictetus insist on having a clear framework that precedes decision-making. Don''t improvise your principles under fire.', '{"clarity","discipline"}', '{"ethical framework","principled decision-making","authority of wisdom"}', 'When facing a moral dilemma under time pressure. When you do not have time to deliberate and need pre-established principles to guide you.', 'C', 'Have a framework. Do not improvise your ethics under pressure -- consult your principles, your mentors, your tested sources of wisdom. This verse argues for ethical infrastructure rather than moral improvisation.', true, false, 'Enchiridion text not available in public domain source files; quote sourced from standard translation.');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (81, 17, 3, 'sattvānurūpā sarvasya śraddhā bhavati bhārata', 'The faith of each is in accordance with his nature, O Arjuna! The man consists of his faith; as a man''s faith is, so is he.', 'You are what you actually believe. Not what you say you believe. Not what you post about. What you do when no one''s watching reveals your real faith. If you say you value health but eat garbage, your real belief is that convenience matters more. If you say you value honesty but dodge hard conversations, your real belief is that comfort matters more. This verse is an invitation to radical self-honesty.', 'Look at how you actually spent the last 24 hours. What do your actions say you believe in? Does that match what you''d tell people you believe?', 'What is the gap between what you say matters to you and what your behavior actually reveals?', 'Death lies heavy upon one who, known exceedingly well by all, dies unknown to himself.', 'Seneca, Thyestes, 400', 'Both Krishna and Seneca probe the same gap: you can be known by everyone else and still be a stranger to yourself. Your operative beliefs may be invisible to you.', '{"clarity","perspective"}', '{"operative faith","belief shapes reality","self-honesty"}', 'When your actions consistently contradict your stated values. When you need to examine what you actually believe, not what you say you believe.', 'C', 'You are what you believe at the deepest level. Not your stated beliefs but your operative faith -- the assumptions you actually live by -- shape your entire life. This verse demands radical honesty about what you truly believe.', true, false, 'source: Thyestes (tragedy), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (82, 17, 14, 'deva-dvija-guru-prājña-pūjanaṁ śaucam ārjavam', 'Worship of the gods, the twice-born, the teachers and the wise, purity, straightforwardness, celibacy and non-injury, these are called the austerities of the body.', 'There are three levels of discipline. Body: how you treat others, how you carry yourself, how you show up physically. Speech: what you say, how you say it, whether it''s true and kind. Mind: your inner calm, your intentions, your self-control. Most people only work on one. The person who works on all three at once doesn''t just become more disciplined. They become a different kind of person.', 'For the next hour, before you say anything, run it through a quick filter: is it true? Is it kind? Is it necessary? You''ll be surprised how much you don''t say.', 'Which of the three (body, speech, mind) is your weakest area of discipline right now?', 'Forbear henceforth to complain of the trouble of a courtly life, either in public before others, or in private by thyself.', 'Marcus Aurelius, Meditations, 8.9', 'Both the Gita and Marcus recognize that discipline of speech is a critical lever for character development. What you say, even to yourself, shapes who you become.', '{"discipline","patience"}', '{"three-level refinement","body-speech-mind","daily practice"}', 'When you want a structured self-improvement practice that covers body, speech, and mind. When you need specific targets for daily refinement.', 'B', 'A three-level practice for personal refinement: body (reverence, purity, non-violence), speech (truthful, pleasant, beneficial), and mind (serenity, gentleness, self-control). Immediately actionable and applicable to any given moment.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (83, 18, 6, 'etāny api tu karmāṇi saṅgaṁ tyaktvā phalāni ca', 'But even these actions should be performed leaving aside attachment and the desire for rewards, O Arjuna! This is My certain and best conviction.', 'This is Krishna''s final word on action, and it''s crystal clear: do what needs doing. Drop the attachment. Drop the craving for results. This isn''t uncertainty. It''s stated as absolute conviction. After 18 chapters of nuance, this is the bottom line. Act. Let go. Repeat.', 'Pick your biggest task today. Before you start, say: ''I''m doing this because it needs doing, not because of what I''ll get from it.'' Then begin.', 'How would the quality of your work change if you truly didn''t care about the reward?', 'We should try by all means to be as grateful as possible. For gratitude is a good thing for ourselves, in a sense in which justice, that is commonly supposed to concern other persons, is not; gratitude returns in large measure unto itself.', 'Seneca, Moral Letters, 81.19', 'Both Krishna and Seneca describe the final posture of the mature actor: do what must be done with gratitude rather than grasping. Let the act itself be its own reward.', '{"discipline","acceptance"}', '{"ultimate conclusion","release attachment","final instruction"}', 'When you need the final, authoritative instruction on how to act. When all the nuances have been explored and you need the bottom line.', 'C', 'Krishna''s final word on action: do what must be done, but release attachment to both the activity itself and its rewards. This is the culmination of the entire Gita''s teaching on karma yoga, stated with absolute finality.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (84, 18, 9, 'kāryam ity eva yat karma niyataṁ kriyate ''rjuna', 'Whatever obligatory action is done, O Arjuna, merely because it ought to be done, abandoning attachment and also the desire for reward, that renunciation is regarded as Sattwic!', 'The highest form of letting go isn''t quitting. It''s doing everything that needs doing while releasing your grip on how it turns out. You still show up. You still give your best. You just stop clenching around the outcome. It''s the difference between a tight fist and an open hand. The open hand can hold more.', 'Notice the next time you check for results after doing something (likes, replies, feedback). Catch yourself and redirect your attention back to the next task.', 'What would it feel like to do excellent work and then just... walk away from it?', 'Fancy not to thyself things future, as though they were present but of those that are present, take some aside, that thou takest most benefit of, and consider of them particularly, how wonderfully thou wouldst want them, if they were not present.', 'Marcus Aurelius, Meditations, 7.27', 'Both Krishna and Marcus point toward contentment in action: do what''s needed with what you have, without grasping for what lies beyond your reach.', '{"acceptance","discipline"}', '{"sattvic renunciation","full engagement","detached action"}', 'When you understand non-attachment intellectually but struggle with it in practice. When you need to see what truly detached action looks like.', 'C', 'The highest form of letting go: you still do everything that needs doing -- you just stop clinging to how it turns out. Sattvic renunciation is not withdrawal; it is full engagement minus attachment.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (85, 18, 11, 'na hi deha-bhṛtā śakyaṁ tyaktuṁ karmāṇy aśeṣataḥ', 'Verily, it is not possible for an embodied being to abandon actions entirely; but he who relinquishes the rewards of actions is verily called a man of renunciation.', 'You can''t stop acting. As long as you have a body, you''re doing things. Eating, breathing, thinking. The question was never whether to act. It was always whether to cling to what the action produces. Real renunciation isn''t withdrawal. It''s full engagement with an open hand. If you''re fantasizing about quitting everything and moving to a cabin, this verse is talking to you.', 'Think of one result you''ve been obsessing over. Imagine it going either way. Notice: you''re still here. Now get back to the work.', 'What would change about your daily experience if you stopped measuring your actions by their outcomes?', 'The Builder of the universe, who laid down for us the laws of life, provided that we should exist in well-being, but not in luxury.', 'Seneca, Moral Letters, 119.15b', 'Both Krishna and Seneca affirm that well-being doesn''t require withdrawing from life. It requires a right relationship with it.', '{"acceptance","perspective"}', '{"impossibility of inaction","true renunciation","embodied life"}', 'When you fantasize about quitting everything and retreating. When you confuse renunciation with escape.', 'C', 'Perfection is not about doing nothing. As long as you have a body, action is unavoidable. True renunciation is not stopping action but stopping the grip of attachment to outcomes. This verse destroys the escapist''s excuse.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (86, 18, 16, 'tatraivaṁ sati kartāram ātmānaṁ kevalaṁ tu yaḥ', 'Now, such being the case, he who, owing to untrained understanding, looks upon his Self, which is isolated, as the agent, he of perverted intelligence, sees not.', 'You''re never the sole author of any outcome. That project succeeded because of timing, your team, and a dozen factors you didn''t control. That failure wasn''t all your fault either. Taking full personal credit or blame for anything is ego pretending it runs the show. Recognizing the web of causes doesn''t make you passive. It makes you humble. And humble people make better decisions.', 'Think of your most recent accomplishment. Write down three factors that contributed to it that had nothing to do with you personally.', 'Where are you taking too much credit or too much blame for something that involved a hundred other causes?', 'Who can choose but wonder at them? They will not speak well of them that are at the same time with them, and live with them; yet they themselves are very ambitious, that they that shall follow, whom they have never seen, nor shall ever see, should speak well of them.', 'Marcus Aurelius, Meditations, 6.18', 'Both Krishna and Marcus expose the ego''s delusion of sole authorship. Results arise from causes far beyond your individual will.', '{"perspective","acceptance"}', '{"web of causation","ego deflation","shared authorship"}', 'When success goes to your head or failure crushes you. When you need to see the complex web of causes behind any outcome.', 'C', 'You are never the sole author of any outcome. Recognizing the web of causes frees you from both grandiosity when things go well and crushing self-blame when they do not.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (87, 18, 20, 'sarva-bhūteṣu yenaikaṁ bhāvam avyayam īkṣate', 'That by which one sees the one indestructible Reality in all beings, not separate in all the separate beings, know thou that knowledge to be Sattwic (pure).', 'The highest knowledge isn''t knowing more facts. It''s seeing one thing in everything. The same reality in your friend and your enemy. The same substance in a tree and a person. The same presence in birth and death. This isn''t mystical hand-waving. It''s a specific way of perceiving that makes you calmer, kinder, and harder to provoke. Because when you see unity, there''s nothing left to fight.', 'Look at two people who seem totally different from each other. Find one thing they have in common at the most basic level. That''s the practice.', 'When do you feel most separated from others, and what would shift if you saw what you share instead?', 'He that knoweth not what the world is, knoweth not where he himself is. And he that knoweth not what the world was made for, cannot possibly know either what are the qualities, or what is the nature of the world.', 'Marcus Aurelius, Meditations, 8.52', 'Both Krishna and Marcus point toward seeing the whole rather than the fragment. True knowledge requires perceiving the unity that connects all things.', '{"perspective","clarity"}', '{"unity in diversity","sattvic knowledge","non-dual perception"}', 'When tribalism or polarization narrows your vision. When you need to zoom out and see the common thread running through apparently different people and situations.', 'C', 'The highest knowledge is seeing unity beneath diversity -- not as theory but as lived perception. Sattvic knowledge does not divide the world into fragments; it perceives the one changeless reality in all changing forms.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (88, 18, 23, 'niyataṁ saṅga-rahitam arāga-dveṣataḥ kṛtam', 'An action which is ordained, which is free from attachment, which is done without love or hatred by one who is not desirous of any reward, that action is declared to be Sattwic.', 'Here''s a five-point test for any action. Is it the right thing to do? Are you unattached to the outcome? Are you acting without favoritism or resentment? Are you not chasing a reward? If yes to all five, congratulations. That''s the purest form of action the Gita describes. If you hit three out of five, you''re doing better than most.', 'Before your next important action today, run it through the five-point test. You''ll see which ones you pass easily and which need work.', 'Which element of pure action is hardest for you: doing the right thing, releasing attachment, acting without bias, or not chasing rewards?', 'What, then, is that which makes a man free from hindrance and makes him his own master? For wealth does not do it, nor consulship, nor provincial government, nor royal power; but something else must be discovered. Therefore in life also it is the science of life.', 'Epictetus, Discourses, 4.1.62-64', 'Both Krishna and Epictetus converge on the same conclusion: excellent action comes from inner knowledge of how to engage rightly with life, not from external conditions.', '{"discipline","clarity"}', '{"sattvic action","decision framework","excellence criteria"}', 'When evaluating whether an action you are about to take meets the standard of excellence. When you need a quick five-point test for any decision.', 'B', 'The complete description of excellent action: ordained, without attachment, without passion or hatred, without desire for fruits. A standard you can measure any decision against -- five criteria in one verse.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (89, 18, 26, 'mukta-saṅgo ''nahaṁ-vādī dhṛty-utsāha-samanvitaḥ', 'He who is free from attachment, non-egoistic, endowed with firmness and enthusiasm and unaffected by success or failure, is called Sattwic.', 'Free from attachment. Non-egoistic. Firm. Enthusiastic. Unaffected by success or failure. That''s the portrait of someone who''s genuinely dangerous in the best way. They can''t be bought, flattered, or intimidated. They show up with energy because the work matters, not because they need the win. If you''ve ever met someone like this, you remember them. They''re rare.', 'Think of the last time success went to your head or failure crushed your spirit. Imagine responding to both with the same steady energy. That''s the target.', 'How different would your work be if success and failure genuinely didn''t change how you felt about yourself?', 'Remember that thy mind is of that nature as that it becometh altogether unconquerable, when once recollected in herself, she seeks no other content than this, that she cannot be forced. And therefore let thy chief fort and place of defence be, a mind free from passions.', 'Marcus Aurelius, Meditations, 8.48', 'Both the Gita and Marcus define the ideal actor as an inner fortress: free from ego and passions, relying on an unconquerable inner resolve that doesn''t shift with results.', '{"courage","discipline"}', '{"sattvic actor","humble leadership","resilient effectiveness"}', 'When in a leadership role and tempted to lead through ego or force. When you need a model for effective action that does not depend on self-importance.', 'B', 'The sattvic actor: free of attachment, never speaks from ego, resolute, steady, unmoved by success or failure. This is a leadership profile that transcends culture -- effective, humble, and unshakeable.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (90, 18, 30, 'pravṛttiṁ ca nivṛttiṁ ca kāryākārye bhayābhaye', 'That which knows the path of work and renunciation, what ought to be done and what ought not to be done, fear and fearlessness, bondage and liberation, that intellect is Sattwic, O Arjuna!', 'Clear thinking has specific outputs. You know when to act and when to stop. You know what''s actually threatening and what''s just noise. You know what binds you and what frees you. That''s not intelligence in the IQ sense. It''s wisdom in the practical sense. And it''s worth more than any credential because it actually works when things get hard.', 'Write down one thing you''re currently afraid of. Ask: is this a real threat, or am I sending my thoughts too far ahead?', 'What are you afraid of right now that, if you looked closely, isn''t actually dangerous?', '''Cease to hope,'' he says, ''and you will cease to fear.'' The chief cause of both these ills is that we do not adapt ourselves to the present, but send our thoughts a long way ahead.', 'Hecato, quoted in Seneca, Moral Letters, 5.7b-8', 'Both the Gita and Seneca address the core of discernment: knowing what to truly fear, what to engage, and what to release.', '{"clarity","courage"}', '{"discernment","when to act","sattvic intelligence"}', 'When paralyzed by too many options. When you need the clarity to distinguish between real threats and imagined ones, between necessary action and busy-work.', 'B', 'Clear thinking defined: knowing when to act and when to refrain, what truly threatens you and what does not, what binds and what liberates. Sattvic intelligence is the operating system behind all good decisions.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (91, 18, 33, 'dhṛtyā yayā dhārayate manaḥ-prāṇendriya-kriyāḥ', 'The unwavering firmness by which, through Yoga, the functions of the mind, the life-force and the senses are restrained, that firmness, O Arjuna, is Sattwic!', 'Resolve is what separates the serious from the dabblers. Not talent, not insight, not motivation. Resolve. The kind that holds your mind steady when everything inside you wants to quit. The kind that keeps your senses in check when every impulse is screaming. This isn''t willpower, which is a depleting resource. It''s commitment, which runs on something deeper.', 'Think of one commitment you''ve made to yourself that you keep breaking. Recommit to it right now, but make it smaller and more specific. Then keep it. Today.', 'What''s the difference between the commitments you keep and the ones you don''t? What does that tell you?', 'If the breaking day sees someone proud, the ending day sees them brought low. No one should put too much trust in triumph, no one should give up hope of trials improving.', 'Seneca, Thyestes, 613', 'Both Krishna and Seneca understand that fortune is a wheel that never stops turning. Sattvic resolve holds steady regardless, because it stopped trusting the wheel.', '{"discipline","patience"}', '{"resolve","unshakeable commitment","practice over talent"}', 'When your commitment to a practice or path is wavering. When you need to remember that resolve, not inspiration, is what carries you through.', 'B', 'Sattvic resolve: unshakeable commitment to practice that holds the mind, breath, and senses steady. This is what separates the serious practitioner from the dabbler -- not talent, but consistency of commitment.', true, false, 'source: Thyestes (tragedy), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (92, 18, 37, 'yat tad agre viṣam iva pariṇāme ''mṛtopamam', 'That which is like poison at first but in the end like nectar, that pleasure is declared to be Sattwic, born of the purity of one''s own mind due to Self-realisation.', 'The workout is miserable for the first ten minutes. The meditation feels pointless for the first two weeks. The difficult conversation is awful in the moment. But afterward, every single one of these leaves you better than you found yourself. Meanwhile, the easy shortcut tastes great going down and terrible sitting in your stomach. Choose your poison. Literally.', 'Do one thing today that feels unpleasant but you know is good for you. Start the workout, have the conversation, clean the thing. The nectar is on the other side.', 'What ''poison'' have you been avoiding that you know would eventually become nectar?', 'Success comes to the lowly and to the poorly talented, but the special characteristic of a great person is to triumph over the disasters and panics of human life.', 'Seneca, On Providence, 4.1', 'Both the Gita and Seneca affirm that difficulty at the beginning is not a sign of a wrong path. Greatness is forged by enduring what feels hard until the reward appears.', '{"patience","discipline"}', '{"delayed gratification","poison to nectar","long-term thinking"}', 'When a new discipline feels terrible and you want to quit. When you need to trust the process through the bitter beginning.', 'A', 'The most practical wisdom in the Gita''s final chapter: what feels like poison at first becomes nectar. Every worthwhile practice is hard at the beginning and rewarding later. Every cheap pleasure is the reverse. Choose accordingly.', true, false, 'source: On Providence (essay), not in available public domain texts, needs manual verification');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (93, 18, 38, 'viṣayendriya-saṁyogād yat tad agre ''mṛtopamam', 'That pleasure which arises from the contact of the sense-organs with the objects, which is at first like nectar and in the end like poison, that is declared to be Rajasic.', 'It tastes amazing going down and terrible sitting in your stomach. That''s rajasic pleasure in one image. The second donut, the third drink, the argument you ''won,'' the purchase that felt urgent. All nectar at first, all poison eventually. The Gita isn''t anti-pleasure. It''s asking you to fast-forward the tape before you hit play.', 'Before your next impulse purchase or indulgence today, fast-forward 24 hours. How will you feel about it then? Let the answer guide you.', 'What pleasure in your life started as nectar and has quietly become poison?', 'Remember, then, if you deem what is by nature slavish to be free, and what is not your own to be yours, you will be shackled and miserable.', 'Epictetus, Enchiridion, 1.3', 'Both Krishna and Epictetus warn about the trajectory of sense pleasure: mistaking what''s temporary for what''s yours leads to bondage and regret.', '{"perspective","discipline"}', '{"hedonic treadmill","rajasic pleasure","dopamine trap"}', 'When caught in a cycle of indulgence and regret. When you need to see the complete trajectory of a pleasure before you chase it.', 'C', 'The hedonic treadmill diagnosed in one verse: pleasure from sense contact starts sweet and ends bitter. Every dopamine hit that leaves you emptier than before. The Gita names the pattern 2,500 years before behavioral psychology.', true, false, 'Enchiridion text not available in public domain source files; quote sourced from standard translation.');
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (94, 18, 47, 'śreyān sva-dharmo viguṇaḥ para-dharmāt sv-anuṣṭhitāt', 'Better is one''s own duty (though) destitute of merits, than the duty of another well performed. He who does the duty ordained by his own nature incurs no sin.', 'This verse appears twice in the Gita. That''s how much it matters. Your clumsy, imperfect, authentic work beats a polished imitation of someone else''s path. Every single time. Stop looking at what your neighbor is building and build the thing that''s yours.', 'Unfollow or mute one account that makes you feel like you should be living a different life.', 'What would you build if you stopped looking at what everyone else is building?', 'What is there remaining that should be dear unto thee? This I think: that in all thy motions and actions thou be moved, and restrained according to thine own true natural constitution and construction only.', 'Marcus Aurelius, Meditations, 6.16', 'Both the Gita and Marcus say the same thing: prize your own nature, your own path. Harmony comes from honoring your own duty, not from imitating another''s.', '{"clarity","courage"}', '{"svadharma","authenticity","stop comparing"}', 'When envying someone else''s career, talent, or life. When comparison paralysis prevents you from committing to your own work.', 'A', 'Repeated from 3.35 in the final chapter for emphasis: your own imperfect path is superior to another''s perfect one. This is the Gita''s most urgent plea against comparison, imitation, and inauthenticity.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (95, 18, 48, 'saha-jaṁ karma kaunteya sa-doṣam api na tyajet', 'One should not abandon, O Arjuna, the duty to which one is born, though faulty; for, all undertakings are enveloped by evil, as fire by smoke!', 'Every fire produces smoke. Every project has problems. Every person has flaws. If you''re waiting for a perfect, clean version of the thing you need to do, you''ll wait forever. Imperfection isn''t a bug. It''s a feature of being alive. Start anyway.', 'Ship that thing you''ve been polishing. Send the email you''ve been rewriting. Post the work you''ve been holding back. It''s good enough.', 'What have you been refusing to start because you can''t guarantee it''ll be perfect?', 'Not as though thou hadst thousands of years to live. Death hangs over thee: whilst yet thou livest, whilst thou mayest, be good.', 'Marcus Aurelius, Meditations, 4.17', 'Both the Gita and Marcus cut through perfectionism with the same urgency: you''ll never do it perfectly, and you''re running out of time. Start now.', '{"courage","acceptance"}', '{"imperfection is inherent","anti-perfectionism","begin anyway"}', 'When perfectionism prevents you from shipping, publishing, starting, or committing. When you need permission to begin despite knowing the result will be imperfect.', 'A', 'All action is tainted by some fault, as fire is tainted by smoke. Imperfection is inherent to every endeavor. This is not a reason to quit -- it is a reason to begin. The verse demolishes perfectionism as an excuse for inaction.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (96, 18, 58, 'mac-cittaḥ sarva-durgāṇi mat-prasādāt tariṣyasi', 'Fixing thy mind on Me, thou shalt by My Grace overcome all obstacles; but if from egoism thou wilt not hear Me, thou shalt perish.', 'Align with something bigger than yourself and obstacles become passable. Insist on doing everything from ego and those same obstacles will break you. This isn''t about religion. It''s about the difference between purposeful persistence and stubborn pride. One bends around rocks and keeps flowing. The other slams into them and shatters.', 'Identify one obstacle you''re fighting with force right now. Ask: is there a way to work with it instead of against it?', 'Where are you holding on because of purpose, and where are you holding on because of pride? Can you tell the difference?', 'So that what before was the impediment, is now the principal object of her working; and that which before was in her way, is now her readiest way.', 'Marcus Aurelius, Meditations, 5.20', 'Both Krishna and Marcus offer the same remedy: when aligned with something larger than ego, obstacles don''t block your path. They become the path.', '{"courage","acceptance"}', '{"alignment with purpose","ego vs. surrender","overcoming obstacles"}', 'When perseverance has become stubbornness. When you need to distinguish between holding on because of purpose and holding on because of pride.', 'C', 'Alignment with your deepest purpose gets you through any difficulty. But ego-driven stubbornness destroys. The verse distinguishes between purposeful persistence and prideful rigidity.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (97, 18, 63, 'iti te jñānam ākhyātaṁ guhyād guhyataraṁ mayā', 'Thus has wisdom more secret than secrecy itself been declared unto thee by Me; having reflected over it fully, then act thou as thou wishest.', 'After 18 chapters of the most profound spiritual teaching ever delivered, Krishna''s last word is: ''Now decide for yourself.'' No ultimatum. No threat. Just, ''I''ve told you what I know. Think about it. Do what you think is right.'' That''s the deepest respect anyone can show you.', 'Think of the last piece of advice you received that felt right. Stop waiting for more information. Act on it today.', 'What do you already know that you''re pretending you still need to research?', 'Show me that the good in life does not depend upon life''s length, but upon the use we make of it; also, that it is possible, or rather usual, for a man who has lived long to have lived too little.', 'Seneca, Moral Letters, 49.10b', 'Both Krishna and Seneca treat you as a free agent: wisdom is offered freely, but the decision of how to live is yours alone.', '{"clarity","courage"}', '{"autonomy","personal responsibility","freedom of choice"}', 'When you have received enough counsel and need to decide. When the time for learning ends and the time for choosing begins.', 'A', 'The ultimate respect for human autonomy: even after delivering the entire Gita, Krishna says ''I have told you what I know -- now think it through and decide for yourself.'' No coercion, no ultimatum. The highest teaching ends in freedom.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (98, 18, 66, 'sarva-dharmān parityajya mām ekaṁ śaraṇaṁ vraja', 'Abandoning all duties, take refuge in Me alone; I will liberate thee from all sins; grieve not.', 'After all the analysis, all the practice, all the frameworks, sometimes you just have to let go. Not give up. Let go. Trust that the effort you''ve put in has done its work and release your grip on the steering wheel. This isn''t passivity. It''s the final act of someone who''s done everything within their power and is now ready to let the rest unfold.', 'Name one thing you''ve been controlling obsessively. Hold it loosely for the rest of the day. See what happens.', 'What would it feel like to trust that you''ve done enough?', 'To suffer change can be no hurt; as no benefit it is, by change to attain to being.', 'Marcus Aurelius, Meditations, 4.42', 'Both the Gita and Marcus arrive at the same place: release all fixed positions. There''s no harm in change, and no lasting safety in clinging.', '{"acceptance","courage"}', '{"surrender","ultimate trust","beyond analysis"}', 'When you have done everything you can and must release. When all effort has been exhausted and only trust remains.', 'A', 'The final instruction of the entire Gita: after all analysis, practice, and discernment, the ultimate move is surrender. Not passive resignation but active trust in something greater than the calculating mind.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (99, 18, 73, 'naṣṭo mohaḥ smṛtir labdhā tvat-prasādān mayācyuta', 'Destroyed is my delusion as I have gained my memory (knowledge) through Thy Grace, O Krishna! I am firm; my doubts are gone. I will act according to Thy word.', 'After 700 verses of the most profound teaching ever delivered, Arjuna says three things. My confusion is gone. My doubts have vanished. I will act. That''s the complete arc. From paralysis to clarity to action. Notice he doesn''t say he understands everything. He says his doubts are gone and he''s ready to move. Sometimes that''s all you need. Not perfect understanding. Just enough clarity to take the next step.', 'Name one thing you''ve been confused about. Ask yourself: do I actually need more information, or do I already know enough to act? If you know enough, act.', 'What would it feel like to say, with genuine conviction, ''My doubts are gone. I will act''?', 'When you are delighted with anything, be delighted as with a thing which is not one of those which cannot be taken away, but as with something of such a kind, as an earthen pot is, or a glass cup, that, when it has been broken, you may remember what it was and may not be troubled.', 'Epictetus, Discourses, 3.24.84-86', 'Both Arjuna and Epictetus arrive at the same resolution: clarity comes when you stop layering your fears and wishes onto reality and accept things as they are.', '{"clarity","courage"}', '{"resolution","doubt dispelled","readiness to act"}', 'When a long period of confusion finally breaks into clarity. When the answer has arrived and the only remaining task is to act on what you now know.', 'B', 'The resolution of the entire text: from paralysis to clarity to action. Arjuna''s confusion is dispelled, his understanding restored, his doubts vanished. This is the arc every person in crisis needs to complete -- not partial clarity but full readiness to act.', true, true, NULL);
INSERT INTO public.verses (id, chapter, verse_number, sanskrit_line, translation, modern_interpretation, action_step, reflection_prompt, stoic_parallel_quote, stoic_parallel_source, stoic_bridge, intent_tags, themes, season_context, priority, why_selected, is_curated, stoic_quote_verified, stoic_quote_note) VALUES (100, 18, 78, 'yatra yogeśvaraḥ kṛṣṇo yatra pārtho dhanur-dharaḥ', 'Wherever there is Krishna, the Lord of Yoga, wherever there is Arjuna, the archer, there are prosperity, happiness, victory and firm policy; such is my conviction.', 'Where wisdom meets action, everything follows. Prosperity, happiness, victory, good judgment. Not from wisdom alone. Not from action alone. From both, together, in the same person. That''s the final message of the entire Gita. You need the clarity AND the willingness to move. The philosopher who never acts and the hustler who never reflects are both incomplete. The magic is in the combination.', 'Think of one area where you have the knowledge but haven''t taken action, and one area where you''ve been acting without thinking. Fix one of them today.', 'Where in your life are wisdom and action currently out of balance, and what would it look like to bring them together?', 'Even as the fire when it prevails upon those things that are in his way; by which things indeed a little fire would have been quenched, but a great fire doth soon turn to its own nature, and so consume whatsoever comes in his way: yea by those very things it is made greater and greater.', 'Marcus Aurelius, Meditations, 10.31', 'Both the Gita and Marcus converge on the same insight: when wisdom and committed action are truly united, everything that comes, obstacles, setbacks, opportunities, becomes fuel.', '{"courage","perspective"}', '{"wisdom plus action","alignment produces results","closing affirmation"}', 'When you have both the knowledge and the skill but have not yet combined them. When you need the final affirmation that wisdom plus committed action is the formula.', 'C', 'Where higher wisdom and committed action come together, everything follows -- fortune, victory, success, and good judgment. The final verse of the Gita is not a theological claim but a practical observation: alignment between knowledge and effort produces results.', true, true, NULL);
